                              className="text-brand-200 hover:text-red-500 p-2 rounded-xl hover:bg-red-50"
                              title="Supprimer"
                            >
                              <Trash2 size={16} />
                            </button>
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                  {filteredExpenses.length === 0 && (
                    <tr>
                      <td colSpan={7} className="py-24 text-center">
