                    {comp.isCompliant ? (
                      <>
                        <CheckCircle2 size={12} />
                        Conforme 2026
                      </>
                    ) : (
                      <>
                        <AlertCircle size={12} />
                        Action Requise : Conformit?? 2026
                      </>
                    )}
                  </button>
                );
              })()}
            </h1>
            <p className="text-brand-500 dark:text-brand-400 mt-1 text-sm">
              Aper??u de votre activit?? et de vos revenus.
            </p>
          </div>
