        >
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 auto-rows-auto">
            {widgetOrder.map((id) => {
              if (isSyncing) {
                if (id === "stats") {
                  return (
                    <React.Fragment key={id}>
                      <StatCardSkeleton />
