                if (id === "performance") {
                  return <ChartSkeleton key={id} />;
                }
                if (id === "activity") {
                  return (
                    <div
                      key={id}
                      className="card-modern p-6 h-75 animate-pulse bg-gray-100 dark:bg-gray-800"
                    />
