                                <stop
                                  offset="95%"
                                  stopColor="#0f172a"
                                  stopOpacity={0}
                                />
                              </linearGradient>
                              <linearGradient
                                id="colorDepenses"
                                x1="0"
                                y1="0"
                                x2="0"
                                y2="1"
                              >
                                <stop
                                  offset="5%"
                                  stopColor="#f87171"
                                  stopOpacity={0.1}
                                />
                                <stop
                                  offset="95%"
                                  stopColor="#f87171"
                                  stopOpacity={0}
                                />
                              </linearGradient>
                            </defs>
                            <CartesianGrid
                              strokeDasharray="3 3"
                              vertical={false}
                              stroke="#f1f5f9"
                            />
                            <XAxis
                              dataKey="name"
                              axisLine={false}
                              tickLine={false}
                              tick={{
                                fill: "#94a3b8",
                                fontSize: 10,
                                fontWeight: 600,
                              }}
                              dy={15}
                            />
                            <YAxis
                              axisLine={false}
                              tickLine={false}
                              tick={{
                                fill: "#94a3b8",
                                fontSize: 10,
                                fontWeight: 600,
                              }}
                              tickFormatter={(value) => `${value / 1000}k`}
                            />
                            <Tooltip
                              contentStyle={{
                                borderRadius: "1.25rem",
                                border: "none",
                                boxShadow:
                                  "0 20px 25px -5px rgba(0,0,0,0.1), 0 10px 10px -5px rgba(0,0,0,0.04)",
                                padding: "16px",
                                backgroundColor: "var(--card-bg)",
                                color: "var(--text-main)",
                                fontSize: "11px",
                                fontWeight: "600",
                              }}
                              formatter={(value) =>
                                typeof value === "number"
                                  ? `${value.toLocaleString("fr-FR")} ???`
                                  : ""
                              }
                            />
                            <Area
                              type="monotone"
                              dataKey="Recettes"
                              stroke="#0f172a"
                              strokeWidth={3}
                              fillOpacity={1}
                              fill="url(#colorRecettes)"
                            />
                            <Area
                              type="monotone"
                              dataKey="D??penses"
                              stroke="#f87171"
                              strokeWidth={3}
                              fillOpacity={1}
                              fill="url(#colorDepenses)"
                            />
                          </AreaChart>
                        </ResponsiveContainer>
                      </div>
                    </div>
                  </SortableWidget>
                );
              }

              if (id === "expenses") {
                return (
                  <SortableWidget
                    key={id}
                    id={id}
                    className="lg:col-span-1 row-span-2"
                  >
                    <div className="card-modern p-8 flex flex-col h-full">
                      <h3 className="text-lg font-bold text-brand-900 dark:text-brand-50 mb-8 font-display">
                        R??partition D??penses
                      </h3>
                      {expensesByCategory.length > 0 ? (
                        <div className="flex flex-col h-full">
                          <div className="h-48 w-full mb-8">
                            <ResponsiveContainer width="100%" height="100%">
                              <PieChart>
                                <Pie
                                  data={expensesByCategory}
                                  cx="50%"
                                  cy="50%"
                                  innerRadius={55}
                                  outerRadius={75}
                                  paddingAngle={8}
                                  dataKey="value"
                                >
                                  {expensesByCategory.map((entry) => (
                                    <Cell
                                      key={entry.name}
                                      fill={
                                        COLORS[
                                          expensesByCategory.indexOf(entry) %
                                            COLORS.length
                                        ]
                                      }
                                    />
                                  ))}
                                </Pie>
                                <Tooltip
                                  formatter={(value) =>
                                    typeof value === "number"
                                      ? `${value.toFixed(2)} ???`
                                      : ""
                                  }
                                  contentStyle={{
                                    borderRadius: "12px",
                                    border: "none",
                                    boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
                                    backgroundColor: "var(--card-bg)",
                                    color: "var(--text-main)",
                                  }}
                                />
                              </PieChart>
                            </ResponsiveContainer>
                          </div>
                          <div className="space-y-4 flex-1 overflow-auto custom-scrollbar pr-2">
                            {expensesByCategory.map((cat, idx) => (
                              <div
                                key={cat.name}
                                className="flex items-center justify-between group"
                              >
                                <div className="flex items-center gap-3">
                                  <div
                                    className={`w-2.5 h-2.5 rounded-full bg-[${COLORS[idx % COLORS.length]}]`}
                                  ></div>
                                  <span className="text-xs font-bold text-brand-600 dark:text-brand-400">
                                    {cat.name}
                                  </span>
                                </div>
                                <div className="text-right">
                                  <span className="text-xs font-black text-brand-900 dark:text-brand-50">
                                    {cat.value.toLocaleString()} ???
                                  </span>
                                </div>
                              </div>
                            ))}
                          </div>
                        </div>
                      ) : (
                        <div className="h-full flex flex-col items-center justify-center text-brand-300 bg-brand-50/50 dark:bg-brand-800/10 rounded-3xl border border-dashed border-brand-100 dark:border-brand-700 p-8">
                          <TrendingDown size={48} className="mb-4 opacity-20" />
                          <p className="text-[10px] font-bold uppercase tracking-widest">
                            Aucune d??pense
                          </p>
                        </div>
                      )}
                    </div>
                  </SortableWidget>
                );
              }

              if (id === "activity") {
                return (
                  <SortableWidget
                    key={id}
                    id={id}
                    className="md:col-span-2 lg:col-span-2 row-span-2"
                  >
                    <div className="card-modern p-8 flex flex-col h-full">
                      <div className="flex justify-between items-center mb-8">
                        <div>
                          <h3 className="text-lg font-bold text-brand-900 dark:text-brand-50 font-display">
                            Activit?? r??cente
                          </h3>
                          <p className="text-xs text-brand-400 font-medium">
                            Vos derni??res transactions
                          </p>
                        </div>
                        <button
                          onClick={() => onNavigate("invoices")}
                          aria-label="Afficher toutes les factures"
                          className="text-[10px] font-bold text-brand-600 hover:text-brand-900 dark:text-brand-400 dark:hover:text-brand-50 transition-colors flex items-center uppercase tracking-widest"
                        >
                          Tout voir{" "}
                          <ArrowRight
                            size={14}
                            className="ml-1.5"
                            aria-hidden="true"
                          />
                        </button>
                      </div>

                      <div className="flex-1 overflow-auto -mx-2 px-2 custom-scrollbar">
                        <div className="space-y-2">
                          {recentActivity.map(
                            (
                              item:
                                | Invoice
                                | (Expense & {
                                    activityType: "invoice" | "expense";
                                  }),
                            ) => {
                              const isExpense =
                                "activityType" in item &&
                                item.activityType === "expense";
                              const isInvoice =
                                "activityType" in item &&
                                item.activityType === "invoice";
                              const invoiceStatus = isInvoice
                                ? (item as unknown as Invoice).status
                                : null;
                              let activityIconClass =
                                "bg-brand-50 dark:bg-brand-800/50 text-brand-500";
                              if (invoiceStatus === InvoiceStatus.PAID) {
                                activityIconClass =
                                  "bg-accent-50 dark:bg-accent-900/20 text-accent-600 dark:text-accent-400";
                              } else if (invoiceStatus === InvoiceStatus.SENT) {
                                activityIconClass =
                                  "bg-amber-50 dark:bg-amber-900/20 text-amber-600 dark:text-amber-400";
                              }
                              const iconClass = isInvoice
                                ? activityIconClass
                                : "bg-red-50 dark:bg-red-900/20 text-red-500";
                              let activityBadgeClass =
                                "bg-brand-50 dark:bg-brand-800/50 text-brand-600";
                              if (invoiceStatus === InvoiceStatus.PAID) {
                                activityBadgeClass =
                                  "bg-accent-50 dark:bg-accent-900/20 text-accent-700 dark:text-accent-400";
                              } else if (invoiceStatus === InvoiceStatus.SENT) {
                                activityBadgeClass =
                                  "bg-amber-50 dark:bg-amber-900/20 text-amber-700 dark:text-amber-400";
                              }
                              const badgeClass = isInvoice
                                ? activityBadgeClass
                                : "bg-red-50 dark:bg-red-900/20 text-red-700";
                              let activityItemLabel = (item as Invoice).number;
                              if (isInvoice)
                                activityItemLabel = (item as unknown as Invoice)
                                  .number;
                              else if (isExpense)
                                activityItemLabel = (item as Expense)
                                  .description;
                              return (
                                <div
                                  key={item.id}
                                  role="link"
                                  tabIndex={0}
                                  aria-label={`D??tails ${isExpense ? `de la d??pense: ${(item as Expense).description}` : `de la facture: ${(item as Invoice).number}`} - ${item.date}`}
                                  onClick={() =>
                                    onNavigate(
                                      "activityType" in item &&
                                        item.activityType === "expense"
                                        ? "accounting"
                                        : "invoices",
                                    )
                                  }
                                  onKeyDown={(e) => {
                                    if (e.key === "Enter" || e.key === " ") {
                                      e.preventDefault();
                                      onNavigate(
                                        "activityType" in item &&
                                          item.activityType === "expense"
                                          ? "accounting"
                                          : "invoices",
                                      );
                                    }
                                  }}
                                  className="flex items-center justify-between p-4 hover:bg-brand-50 dark:hover:bg-brand-800/50 rounded-2xl transition-all cursor-pointer border border-transparent group"
                                >
                                  <div className="flex items-center gap-4">
                                    <div
                                      className={`w-11 h-11 rounded-xl flex items-center justify-center text-xs font-bold
                                ${iconClass}`}
                                    >
                                      {"activityType" in item &&
                                      item.activityType === "invoice" ? (
                                        <FileText className="w-4.5 h-4.5" />
                                      ) : (
                                        <ShoppingCart className="w-4.5 h-4.5" />
                                      )}
                                    </div>
                                    <div>
                                      <p className="text-sm font-bold text-brand-900 dark:text-brand-50 group-hover:text-brand-950 dark:group-hover:text-white transition-colors">
                                        {activityItemLabel}
                                      </p>
                                      <p className="text-[10px] font-bold text-brand-400 uppercase tracking-wider">
                                        {new Date(
                                          item.date,
                                        ).toLocaleDateString()}
                                      </p>
                                    </div>
                                  </div>
                                  <div className="text-right">
                                    <p
                                      className={`text-sm font-bold ${("activityType" in item && item.activityType === "expense") || (item as unknown as Invoice).type === "credit_note" ? "text-red-500" : "text-brand-900 dark:text-brand-50"}`}
                                    >
                                      {("activityType" in item &&
                                        item.activityType === "expense") ||
                                      (item as unknown as Invoice).type ===
                                        "credit_note"
                                        ? "-"
                                        : ""}
                                      {("total" in item
                                        ? item.total
                                        : (item as unknown as Expense).amount
                                      )?.toLocaleString("fr-FR")}{" "}
                                      ???
                                    </p>
                                    <span
                                      className={`text-[9px] font-bold px-2 py-0.5 rounded-full mt-1.5 inline-block uppercase tracking-[0.05em]
                                   ${badgeClass}`}
                                    >
                                      {"activityType" in item &&
                                      item.activityType === "invoice"
                                        ? (item as unknown as Invoice).status
                                        : "D??pense"}
                                    </span>
                                  </div>
                                </div>
                              );
                            },
                          )}
                        </div>
                      </div>
                    </div>
                  </SortableWidget>
                );
              }

              if (id === "reminders") {
                return (
                  <SortableWidget
                    key={id}
                    id={id}
                    className="md:col-span-1 lg:col-span-1 border-dashed border-2 border-brand-100 dark:border-brand-800 rounded-4xl"
                  >
                    <div className="card-modern p-6 h-full flex flex-col bg-transparent shadow-none">
                      <div className="flex items-center gap-3 mb-6">
                        <div className="p-2.5 bg-brand-50 dark:bg-brand-800 text-brand-900 dark:text-brand-50 rounded-xl">
                          <Zap size={18} />
                        </div>
                        <h3 className="text-sm font-bold text-brand-900 dark:text-brand-50 uppercase tracking-wider">
                          Devis ?? convertir
                        </h3>
                      </div>
                      <div className="space-y-3 flex-1 overflow-y-auto max-h-75 pr-2 custom-scrollbar">
                        {invoices.some(
                          (i) =>
                            i.type === "quote" &&
                            i.status === InvoiceStatus.ACCEPTED,
                        ) ? (
                          <SortableContext
                            items={invoices
                              .filter(
                                (i) =>
                                  i.type === "quote" &&
                                  i.status === InvoiceStatus.ACCEPTED,
                              )
                              .map((q) => `quote-${q.id}`)}
                            strategy={verticalListSortingStrategy}
                          >
                            {invoices
                              .filter(
                                (i) =>
                                  i.type === "quote" &&
                                  i.status === InvoiceStatus.ACCEPTED,
                              )
                              .map((quote) => (
                                <DraggableQuote
                                  key={quote.id}
                                  quote={quote}
                                  onKeyDown={handleKeyDown}
                                />
                              ))}
                          </SortableContext>
                        ) : (
                          <div className="flex flex-col items-center justify-center h-full text-brand-300 py-10 opacity-50">
                            <CheckCircle2
                              size={32}
                              strokeWidth={1}
                              className="mb-2"
                            />
                            <p className="text-[10px] uppercase font-bold tracking-widest text-center">
                              Aucun devis accept?? en attente
                            </p>
                          </div>
                        )}
                      </div>
                      <div className="mt-4 pt-4 border-t border-brand-50 dark:border-brand-800">
                        <p className="text-[9px] text-brand-400 italic">
                          Glissez un devis sur &quot;Facture&quot; pour le
                          convertir.
                        </p>
                      </div>
                    </div>
                  </SortableWidget>
                );
              }

              if (id === "stock") {
                return (
                  <SortableWidget
                    key={id}
                    id={id}
                    className="lg:col-span-1 row-span-2"
                  >
                    <div className="card-modern p-8 flex flex-col h-full">
                      <div className="flex justify-between items-center mb-8">
                        <h3 className="text-lg font-bold text-brand-900 dark:text-brand-50 flex items-center gap-3 font-display">
                          <Package size={20} className="text-red-500" /> Stocks
                        </h3>
                      </div>
                      <div className="space-y-4 flex-1 overflow-auto custom-scrollbar">
                        {lowStockProducts.length > 0 ? (
                          lowStockProducts.slice(0, 4).map((product) => (
                            <div
                              key={product.id}
                              className="p-5 rounded-2xl border bg-red-50 dark:bg-red-900/20 border-red-100 dark:border-red-900/30 flex flex-col gap-3 transition-all hover:scale-[1.01]"
                            >
                              <div className="flex justify-between items-start">
                                <span className="text-[10px] font-bold text-brand-400 uppercase tracking-widest">
                                  {product.sku ?? "SANS SKU"}
                                </span>
                                <span className="text-[9px] font-bold px-2.5 py-1 rounded-full bg-red-100 dark:bg-red-900 text-red-700 dark:text-red-300 uppercase tracking-widest">
                                  Stock bas
                                </span>
                              </div>
                              <div className="flex justify-between items-center">
                                <p className="text-sm font-bold text-brand-900 dark:text-brand-50">
                                  {product.name}
                                </p>
                                <p className="text-sm font-bold text-red-600 dark:text-red-400">
                                  {product.stock} {product.unit ?? "u."}
                                </p>
                              </div>
                              <p className="text-[9px] text-red-400 font-bold uppercase tracking-widest">
                                Seuil : {product.minStock}{" "}
                                {product.unit ?? "u."}
                              </p>
                            </div>
                          ))
                        ) : (
                          <div className="h-full flex flex-col items-center justify-center text-brand-300">
                            <Package
                              size={36}
                              className="mb-3 opacity-20 text-brand-500"
                            />
                            <p className="text-[10px] font-bold uppercase tracking-widest">
                              Stocks OK
                            </p>
                          </div>
                        )}
                      </div>
                    </div>
                  </SortableWidget>
                );
              }

              if (id === "prediction") {
                return (
                  <SortableWidget
                    key={id}
                    id={id}
                    className="col-span-1 md:col-span-2 lg:col-span-2 xl:col-span-4 zen-hidden"
                  >
                    <div className="card-modern p-6 relative overflow-hidden">
                      {/* Alertes seuils dynamiques */}
                      {revenueProjection.alerts.length > 0 && (
                        <div className="mb-5 space-y-2">
                          {revenueProjection.alerts.map((alert, i) => (
                            <div
                              key={i}
                              role="alert"
                              className={`flex items-start gap-3 p-3 rounded-xl text-[11px] font-semibold ${
                                alert.severity === "danger"
                                  ? "bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-300 border border-red-100 dark:border-red-900/30"
                                  : "bg-amber-50 dark:bg-amber-900/20 text-amber-700 dark:text-amber-300 border border-amber-100 dark:border-amber-900/30"
                              }`}
                            >
                              <AlertCircle
                                size={14}
                                className="shrink-0 mt-0.5"
                                aria-hidden="true"
                              />
                              {alert.message}
                            </div>
                          ))}
                        </div>
                      )}

                      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-5">
                        <div>
                          <div className="flex items-center gap-2">
                            <TrendingUp
                              size={16}
                              className="text-accent-600"
                              aria-hidden="true"
                            />
                            <p className="text-[10px] font-bold text-brand-400 uppercase tracking-[0.15em]">
                              Projection CA ??? 6 mois
                            </p>
                          </div>
                          <div className="flex items-baseline gap-3 mt-1">
                            <span className="text-xl font-bold text-brand-900 dark:text-brand-50 font-display">
                              {revenueProjection.forecast[0]
                                ? `~${revenueProjection.forecast[0].projected.toLocaleString("fr-FR")} ???`
                                : "???"}
                            </span>
                            <span className="text-[10px] text-brand-400 font-medium">
                              prochain mois estim??
                            </span>
                            {revenueProjection.monthlyTrend !== 0 && (
                              <span
                                className={`flex items-center text-[10px] font-bold ${
                                  revenueProjection.monthlyTrend >= 0
                                    ? "text-accent-600"
                                    : "text-red-500"
                                }`}
                              >
                                {revenueProjection.monthlyTrend >= 0 ? (
                                  <ArrowUpRight size={12} aria-hidden="true" />
                                ) : (
                                  <ArrowDownRight
                                    size={12}
                                    aria-hidden="true"
                                  />
                                )}
                                {Math.abs(
                                  revenueProjection.monthlyTrend,
                                ).toFixed(0)}{" "}
                                ???/mois
                              </span>
                            )}
                          </div>
                        </div>

                        <div className="flex items-center gap-3">
                          {revenueProjection.confidence > 0 && (
                            <span className="text-[9px] font-bold text-brand-300 uppercase tracking-wider">
                              Fiabilit?? :{" "}
                              {Math.round(revenueProjection.confidence * 100)}%
                            </span>
                          )}
                          <button
                            onClick={() => {
                              void handlePredict();
                            }}
                            disabled={isPredicting}
                            aria-label={
                              isPredicting
                                ? "Analyse IA en cours..."
                                : "Analyse IA du CA"
                            }
                            className="flex items-center gap-2 bg-brand-600 dark:bg-white text-white dark:text-brand-900 px-4 py-2 rounded-xl text-[10px] font-bold uppercase tracking-wide transition-all hover:bg-brand-700 dark:hover:bg-brand-50 shadow-lg shadow-brand-600/20"
                          >
                            {isPredicting ? (
                              <Loader2
                                size={12}
                                className="animate-spin"
                                aria-hidden="true"
                              />
                            ) : (
                              <Sparkles size={12} aria-hidden="true" />
                            )}
                            Analyse IA
                          </button>
                        </div>
                      </div>

                      {/* Graphique projection */}
                      {revenueProjection.forecast.length > 0 ? (
                        <ResponsiveContainer width="100%" height={180}>
                          <AreaChart
                            data={[
                              ...revenueProjection.history
                                .slice(-3)
                                .map((h) => ({
                                  name: h.month.slice(5),
                                  Historique: h.revenue,
                                  Projection: null as number | null,
                                })),
                              ...revenueProjection.forecast.map((f) => ({
                                name: f.month.slice(5),
                                Historique: null as number | null,
                                Projection: f.projected,
                              })),
                            ]}
                            margin={{ top: 5, right: 10, left: -20, bottom: 0 }}
                          >
                            <defs>
                              <linearGradient
                                id="grad-hist"
                                x1="0"
                                y1="0"
                                x2="0"
                                y2="1"
                              >
                                <stop
                                  offset="5%"
                                  stopColor="#0f172a"
                                  stopOpacity={0.15}
                                />
                                <stop
                                  offset="95%"
                                  stopColor="#0f172a"
                                  stopOpacity={0}
                                />
                              </linearGradient>
                              <linearGradient
                                id="grad-proj"
                                x1="0"
                                y1="0"
                                x2="0"
                                y2="1"
                              >
                                <stop
                                  offset="5%"
                                  stopColor="#22c55e"
                                  stopOpacity={0.2}
                                />
                                <stop
                                  offset="95%"
                                  stopColor="#22c55e"
                                  stopOpacity={0}
                                />
                              </linearGradient>
                            </defs>
                            <CartesianGrid
                              strokeDasharray="3 3"
                              stroke="#f1f5f9"
                              vertical={false}
                            />
                            <XAxis
                              dataKey="name"
                              tick={{ fontSize: 9 }}
                              tickLine={false}
                              axisLine={false}
                            />
                            <YAxis
                              tick={{ fontSize: 9 }}
                              tickLine={false}
                              axisLine={false}
                              tickFormatter={(v) => `${(v / 1000).toFixed(0)}k`}
                            />
                            <Tooltip
                              formatter={(value, name) =>
                                value !== null
                                  ? [
                                      `${Number(value).toLocaleString("fr-FR")} ???`,
                                      String(name),
                                    ]
                                  : ["-", String(name)]
                              }
                              contentStyle={{ fontSize: 10, borderRadius: 12 }}
                            />
                            <Area
                              type="monotone"
                              dataKey="Historique"
                              stroke="#0f172a"
                              fill="url(#grad-hist)"
                              strokeWidth={2}
                              dot={false}
                              connectNulls
                            />
                            <Area
                              type="monotone"
                              dataKey="Projection"
                              stroke="#22c55e"
                              fill="url(#grad-proj)"
                              strokeWidth={2}
                              strokeDasharray="5 3"
                              dot={false}
                              connectNulls
                            />
                          </AreaChart>
                        </ResponsiveContainer>
                      ) : (
                        <div className="flex items-center justify-center h-32 text-brand-300 text-[10px] font-bold uppercase tracking-widest">
                          Pas encore assez de donn??es historiques
                        </div>
                      )}

                      {/* Analyse IA */}
                      {prediction && (
                        <div className="mt-4 p-4 bg-brand-50 dark:bg-brand-800/30 rounded-2xl border border-brand-100 dark:border-brand-800">
                          <div className="flex items-start gap-2">
                            <Sparkles
                              size={12}
                              className="text-accent-600 shrink-0 mt-0.5"
                              aria-hidden="true"
                            />
                            <p className="text-[10px] text-brand-600 dark:text-brand-300 leading-relaxed">
                              {prediction}
                            </p>
                          </div>
                        </div>
                      )}
                    </div>
                  </SortableWidget>
                );
              }

              return null;
            })}
          </div>
        </SortableContext>
      </DndContext>
    </div>
  );
};

export default Dashboard;

import {
  CircleAlert as AlertCircle,
  Check,
  CircleCheck as CheckCircle2,
  Clock,
  Copy,
  Pencil as Edit2,
  Eye,
  FileText,
  History,
  Mail,
  Plus,
  Search,
  Send,
  Trash2,
  User,
  Wand as Wand2,
  X,
} from "lucide-react";
import React, { useMemo, useState } from "react";
import { toast } from "sonner";
import useNotificationsSound from "../hooks/useNotificationsSound";
import { draftEmail } from "../services/geminiService";
import type {
  Client,
  Email,
  EmailTemplate,
  Invoice,
  UserProfile,
} from "../types";

interface EmailManagerProps {
  emails: Email[];
  setEmails: (_emails: Email[]) => void;
  templates: EmailTemplate[];
  setTemplates: (_templates: EmailTemplate[]) => void;
  clients: Client[];
  invoices: Invoice[];
  userProfile: UserProfile;
  onSaveEmail?: (_email: Email) => void;
  onDeleteEmail?: (_id: string) => void;
  onSaveTemplate?: (_template: EmailTemplate) => void;
  onDeleteTemplate?: (_id: string) => void;
}

const EmailManager: React.FC<EmailManagerProps> = ({
  emails,
  setEmails,
  templates,
  setTemplates,
  clients,
  invoices,
  userProfile,
  onSaveEmail,
  onDeleteEmail,
  onSaveTemplate,
  onDeleteTemplate,
}) => {
  const [activeTab, setActiveTab] = useState<
    "history" | "compose" | "templates"
  >("history");
  const [searchTerm, setSearchTerm] = useState("");
  const [isComposeOpen, setIsComposeOpen] = useState(false);
  const [editingTemplateId, setEditingTemplateId] = useState<string | null>(
    null,
  );
  const [isDrafting, setIsDrafting] = useState(false);
  const [showPreview, setShowPreview] = useState(false);
  const [copied, setCopied] = useState(false);
  const { playSound } = useNotificationsSound();

  const [composeData, setComposeData] = useState({
    to: "",
    subject: "",
    body: "",
    type: "custom" as Email["type"],
    relatedId: "",
    clientId: "",
    invoiceId: "",
  });

  const [templateFormData, setTemplateFormData] = useState<
    Partial<EmailTemplate>
  >({
    name: "",
    subject: "",
    body: "",
    type: "custom",
  });

  const filteredEmails = useMemo(() => {
    return emails
      .filter(
        (e) =>
          e.to.toLowerCase().includes(searchTerm.toLowerCase()) ||
          e.subject.toLowerCase().includes(searchTerm.toLowerCase()),
      )
      .sort(
        (a, b) => new Date(b.sentAt).getTime() - new Date(a.sentAt).getTime(),
      );
  }, [emails, searchTerm]);

  const handleAIDraft = async () => {
    const client = clients.find((c) => c.id === composeData.clientId);
    const invoice = invoices.find((i) => i.id === composeData.invoiceId);

    if (!client) {
      alert("Veuillez s??lectionner un client pour g??n??rer un brouillon.");
      return;
    }

    setIsDrafting(true);
    try {
      const draft = await draftEmail({
        clientName: client.name,
        invoiceNumber: invoice?.number,
        total: invoice?.total.toString(),
        purpose:
          composeData.type === "reminder"
            ? "Relance de facture impay??e"
            : composeData.type === "invoice"
              ? "Envoi de facture"
              : composeData.type === "quote"
                ? "Envoi de devis"
                : "Communication diverse",
        tone: "formal",
        companyName: userProfile.companyName,
      });

      setComposeData({
        ...composeData,
        subject: draft.subject,
        body: draft.body,
      });
    } catch (error) {
      console.error(error);
    } finally {
      setIsDrafting(false);
    }
  };

  const handleCopy = () => {
    void navigator.clipboard.writeText(composeData.body);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleSendEmail = (e: React.FormEvent) => {
    e.preventDefault();
    const newEmail: Email = {
      id: Date.now().toString(),
      to: composeData.to,
      subject: composeData.subject,
      body: composeData.body,
      sentAt: new Date().toISOString(),
      status: "sent",
      type: composeData.type,
      relatedId: composeData.relatedId,
    };
    setEmails([...emails, newEmail]);
    if (onSaveEmail) onSaveEmail(newEmail);
    void playSound("success");
    toast.success("Email envoy?? avec succ??s");
    setIsComposeOpen(false);
    setComposeData({
      to: "",
      subject: "",
      body: "",
      type: "custom" as Email["type"],
      relatedId: "",
      clientId: "",
      invoiceId: "",
    });
    setActiveTab("history");
  };

  const handleSaveTemplate = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingTemplateId) {
      const updatedTemplate = {
        ...templates.find((t) => t.id === editingTemplateId),
        ...templateFormData,
      } as EmailTemplate;
      setTemplates(
        templates.map((t) =>
          t.id === editingTemplateId ? updatedTemplate : t,
        ),
      );
      if (onSaveTemplate) onSaveTemplate(updatedTemplate);
    } else {
      const newTemplate: EmailTemplate = {
        id: Date.now().toString(),
        name: templateFormData.name ?? "Nouveau Template",
        subject: templateFormData.subject ?? "",
        body: templateFormData.body ?? "",
        type: templateFormData.type ?? "custom",
      };
      setTemplates([...templates, newTemplate]);
      if (onSaveTemplate) onSaveTemplate(newTemplate);
    }
    setEditingTemplateId(null);
    setTemplateFormData({ name: "", subject: "", body: "", type: "custom" });
  };

  const applyTemplate = (template: EmailTemplate) => {
    let body = template.body;
    let subject = template.subject;

    const client = clients.find((c) => c.id === composeData.clientId);
    const invoice = invoices.find((i) => i.id === composeData.invoiceId);

    const replacements: Record<string, string> = {
      "{{company_name}}": userProfile.companyName,
      "{{client_name}}": client?.name ?? "Client",
      "{{invoice_number}}": invoice?.number ?? "N/A",
      "{{total}}": invoice ? `${invoice.total.toFixed(2)}???` : "0.00???",
      "{{due_date}}": invoice?.dueDate
        ? new Date(invoice.dueDate).toLocaleDateString()
        : "N/A",
    };

    Object.entries(replacements).forEach(([key, value]) => {
      body = body.replace(new RegExp(key, "g"), value);
      subject = subject.replace(new RegExp(key, "g"), value);
    });

    setComposeData({ ...composeData, subject, body, type: template.type });
  };

  const MAGIC_VARIABLES = [
    { key: "{{company_name}}", label: "Votre Entreprise" },
    { key: "{{client_name}}", label: "Nom du Client" },
    { key: "{{invoice_number}}", label: "N?? Facture" },
    { key: "{{total}}", label: "Montant Total" },
    { key: "{{due_date}}", label: "Date d'??ch??ance" },
  ];

  const deleteEmail = (id: string) => {
    if (confirm("Supprimer cet email de l'historique ?")) {
      setEmails(emails.filter((e) => e.id !== id));
      if (onDeleteEmail) onDeleteEmail(id);
    }
  };

  const deleteTemplate = (id: string) => {
    if (confirm("Supprimer ce template ?")) {
      setTemplates(templates.filter((t) => t.id !== id));
      if (onDeleteTemplate) onDeleteTemplate(id);
    }
  };

  return (
    <div className="space-y-8 animate-fade-in max-w-7xl mx-auto">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-brand-900">
            Emails & Communications
          </h2>
          <p className="text-brand-500">
            G??rez vos envois de factures, devis et relances.
          </p>
        </div>
        <button
          onClick={() => {
            setComposeData({
              to: "",
              subject: "",
              body: "",
              type: "custom" as Email["type"],
              relatedId: "",
              clientId: "",
              invoiceId: "",
            });
            setActiveTab("compose");
          }}
          className="bg-brand-900 hover:bg-brand-800 text-white px-5 py-2.5 rounded-2xl flex items-center gap-2 transition-all shadow-lg shadow-brand-900/20 font-medium"
        >
          <Plus size={18} />
          Nouveau Message
        </button>
      </div>

      {/* Tabs */}
      <div className="flex bg-white p-1 rounded-2xl border border-brand-100 shadow-sm w-fit">
        <button
          onClick={() => setActiveTab("history")}
          className={`px-6 py-2 rounded-xl text-sm font-bold transition-all flex items-center gap-2 ${activeTab === "history" ? "bg-brand-900 text-white shadow-md" : "text-brand-500 hover:text-brand-700"}`}
        >
          <History size={16} />
          Historique
        </button>
        <button
          onClick={() => setActiveTab("templates")}
          className={`px-6 py-2 rounded-xl text-sm font-bold transition-all flex items-center gap-2 ${activeTab === "templates" ? "bg-brand-900 text-white shadow-md" : "text-brand-500 hover:text-brand-700"}`}
        >
          <FileText size={16} />
          Templates
        </button>
        <button
          onClick={() => setActiveTab("compose")}
          className={`px-6 py-2 rounded-xl text-sm font-bold transition-all flex items-center gap-2 ${activeTab === "compose" ? "bg-brand-900 text-white shadow-md" : "text-brand-500 hover:text-brand-700"}`}
        >
          <Mail size={16} />
          Composer
        </button>
      </div>

      {activeTab === "history" && (
        <div className="space-y-6">
          <div className="relative max-w-md">
            <Search
              className="absolute left-3 top-1/2 -translate-y-1/2 text-brand-400"
              size={18}
            />
            <input
              type="text"
              placeholder="Rechercher un email..."
              className="w-full pl-10 pr-4 py-3 border border-brand-200 rounded-2xl focus:outline-none focus:ring-2 focus:ring-brand-500/50 bg-white shadow-sm transition-all"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="bg-white border border-brand-100 rounded-4xl overflow-hidden shadow-sm">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-brand-900 text-white">
                  <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider">
                    Destinataire
                  </th>
                  <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider">
                    Sujet
                  </th>
                  <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider">
                    Date
                  </th>
                  <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider">
                    Statut
                  </th>
                  <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider text-right">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-brand-50">
                {filteredEmails.map((email) => {
                  const client = clients.find((c) => c.email === email.to);
                  return (
                    <tr
                      key={email.id}
                      className="hover:bg-brand-50/50 transition-colors group"
                    >
                      <td className="px-6 py-4">
                        <div className="font-bold text-brand-900">
                          {client ? client.name : email.to}
                        </div>
                        <div className="text-[10px] text-brand-400 uppercase font-bold flex items-center gap-2">
                          {email.type}
                          {client && (
                            <span className="text-brand-300 font-normal lowercase italic">
                              ({email.to})
                            </span>
                          )}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-sm text-brand-600 truncate max-w-xs">
                        {email.subject}
                      </td>
                      <td className="px-6 py-4 text-sm text-brand-500">
                        {new Date(email.sentAt).toLocaleDateString()}{" "}
                        {new Date(email.sentAt).toLocaleTimeString([], {
                          hour: "2-digit",
                          minute: "2-digit",
                        })}
                      </td>
                      <td className="px-6 py-4">
                        <span
                          className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${
                            email.status === "sent"
                              ? "bg-emerald-50 text-emerald-600"
                              : "bg-red-50 text-red-600"
                          }`}
                        >
                          {email.status === "sent" ? (
                            <CheckCircle2 size={12} />
                          ) : (
                            <AlertCircle size={12} />
                          )}
                          {email.status === "sent" ? "Envoy??" : "??chec"}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button
                          onClick={() => deleteEmail(email.id)}
                          title="Supprimer l'email"
                          className="p-2 text-brand-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all opacity-0 group-hover:opacity-100"
                        >
                          <Trash2 size={16} />
                        </button>
                      </td>
                    </tr>
                  );
                })}
                {filteredEmails.length === 0 && (
                  <tr>
                    <td
                      colSpan={5}
                      className="px-6 py-20 text-center text-brand-400 italic"
                    >
                      Aucun email envoy?? pour le moment.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === "templates" && (
        <div className="space-y-8">
          {/* Nouveau: Editeur de Template si ouvert */}
          {editingTemplateId || (activeTab === "templates" && isComposeOpen) ? (
            <div className="bg-white border-2 border-brand-900 rounded-4xl p-8 shadow-2xl animate-slide-up">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-bold text-brand-900 flex items-center gap-2">
                  <Edit2 size={24} className="text-brand-600" />
                  {editingTemplateId
                    ? "Modifier le Template"
                    : "Nouveau Template"}
                </h3>
                <button
                  onClick={() => setIsComposeOpen(false)}
                  className="p-2 hover:bg-brand-50 rounded-full transition-colors"
                  title="Fermer"
                  aria-label="Fermer"
                >
                  <X size={24} />
                </button>
              </div>

              <form onSubmit={handleSaveTemplate} className="space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div>
                    <label className="block text-xs font-bold text-brand-500 uppercase tracking-widest mb-2">
                      Nom du Template
                    </label>
                    <input
                      type="text"
                      required
                      className="w-full p-4 bg-brand-50 border border-brand-200 rounded-2xl focus:ring-2 focus:ring-brand-500/20 outline-none font-bold"
                      value={templateFormData.name}
                      onChange={(e) =>
                        setTemplateFormData({
                          ...templateFormData,
                          name: e.target.value,
                        })
                      }
                      placeholder="Ex: Facture - Premier Envoi"
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-brand-500 uppercase tracking-widest mb-2">
                      Type
                    </label>
                    <select
                      className="w-full p-4 bg-brand-50 border border-brand-200 rounded-2xl outline-none appearance-none"
                      title="Type de template"
                      value={templateFormData.type}
                      onChange={(e) =>
                        setTemplateFormData({
                          ...templateFormData,
                          type: e.target.value as EmailTemplate["type"],
                        })
                      }
                    >
                      <option value="invoice">Facturation</option>
                      <option value="quote">Devis</option>
                      <option value="reminder">Relance</option>
                      <option value="custom">Autre</option>
                    </select>
                  </div>
                </div>

                <div>
                  <label className="block text-xs font-bold text-brand-500 uppercase tracking-widest mb-2">
                    Sujet de l'Email
                  </label>
                  <input
                    type="text"
                    required
                    className="w-full p-4 bg-brand-50 border border-brand-200 rounded-2xl focus:ring-2 focus:ring-brand-500/20 outline-none font-bold"
                    value={templateFormData.subject}
                    onChange={(e) =>
                      setTemplateFormData({
                        ...templateFormData,
                        subject: e.target.value,
                      })
                    }
                    placeholder="Sujet avec {{invoice_number}}..."
                  />
                </div>

                <div>
                  <div className="flex justify-between items-center mb-2">
                    <label className="block text-xs font-bold text-brand-500 uppercase tracking-widest">
                      Corps du Message
                    </label>
                    <div className="flex gap-1">
                      {MAGIC_VARIABLES.map((v) => (
                        <button
                          key={v.key}
                          type="button"
                          onClick={() =>
                            setTemplateFormData({
                              ...templateFormData,
                              body: (templateFormData.body ?? "") + v.key,
                            })
                          }
                          className="text-[10px] bg-brand-900 text-white px-2 py-1 rounded-lg hover:bg-brand-700 transition-all font-bold"
                          title={v.label}
                        >
                          {v.key}
                        </button>
                      ))}
                    </div>
                  </div>
                  <textarea
                    rows={8}
                    required
                    className="w-full p-6 bg-brand-50 border border-brand-200 rounded-3xl focus:ring-2 focus:ring-brand-500/20 outline-none resize-none font-medium leading-relaxed"
                    value={templateFormData.body}
                    onChange={(e) =>
                      setTemplateFormData({
                        ...templateFormData,
                        body: e.target.value,
                      })
                    }
                    placeholder="Contenu du message..."
                  />
                </div>

                <div className="flex justify-end gap-3 pt-4 border-t border-brand-50">
                  <button
                    type="button"
                    onClick={() => setIsComposeOpen(false)}
                    className="px-8 py-3 text-brand-600 font-bold text-xs uppercase tracking-widest hover:bg-brand-50 rounded-2xl"
                  >
                    Annuler
                  </button>
                  <button
                    type="submit"
                    className="bg-brand-900 text-white px-10 py-3 rounded-2xl hover:bg-brand-800 transition-all shadow-xl font-bold text-xs uppercase tracking-widest"
                  >
                    Enregistrer le Template
                  </button>
                </div>
              </form>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              <button
                onClick={() => {
                  setEditingTemplateId(null);
                  setTemplateFormData({
                    name: "",
                    subject: "",
                    body: "",
                    type: "custom",
                  });
                  setIsComposeOpen(true);
                }}
                className="border-2 border-dashed border-brand-200 rounded-4xl p-8 flex flex-col items-center justify-center gap-4 text-brand-400 hover:text-brand-600 hover:border-brand-400 hover:bg-brand-50 transition-all group min-h-75"
              >
                <div className="w-16 h-16 rounded-full bg-brand-50 flex items-center justify-center group-hover:scale-110 transition-transform">
                  <Plus size={32} />
                </div>
                <span className="font-bold uppercase tracking-wider text-xs">
                  Nouveau Template
                </span>
              </button>

              {templates.map((template) => (
                <div
                  key={template.id}
                  className="bg-white border border-brand-100 rounded-4xl p-6 shadow-sm hover:shadow-md transition-all group relative flex flex-col justify-between"
                >
                  <div>
                    <div className="flex justify-between items-start mb-4">
                      <div className="w-12 h-12 rounded-2xl bg-brand-50 flex items-center justify-center text-brand-600">
                        <FileText size={24} />
                      </div>
                      <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button
                          onClick={() => {
                            setEditingTemplateId(template.id);
                            setTemplateFormData(template);
                            setIsComposeOpen(true);
                          }}
                          title="Modifier le template"
                          className="p-2 text-brand-400 hover:text-brand-600 hover:bg-brand-50 rounded-xl transition-all"
                        >
                          <Edit2 size={16} />
                        </button>
                        <button
                          onClick={() => deleteTemplate(template.id)}
                          title="Supprimer le template"
                          className="p-2 text-brand-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </div>
                    <h4 className="font-bold text-brand-900 mb-1">
                      {template.name}
                    </h4>
                    <span
                      className={`inline-block px-3 py-1 rounded-full text-[9px] font-bold uppercase tracking-wider mb-3 ${
                        template.type === "reminder"
                          ? "bg-orange-50 text-orange-600"
                          : template.type === "invoice"
                            ? "bg-emerald-50 text-emerald-600"
                            : "bg-brand-50 text-brand-600"
                      }`}
                    >
                      {template.type}
                    </span>
                    <div className="text-sm text-brand-600 line-clamp-3 mb-4 bg-brand-50/50 p-3 rounded-xl italic">
                      {template.subject}
                    </div>
                  </div>
                  <button
                    onClick={() => {
                      applyTemplate(template);
                      setActiveTab("compose");
                    }}
                    className="w-full py-2.5 bg-brand-900 text-white rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-brand-800 transition-all shadow-lg"
                  >
                    Utiliser ce template
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {activeTab === "compose" && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2 bg-white border border-brand-100 rounded-4xl p-8 shadow-sm">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-lg font-bold text-brand-900 flex items-center gap-2">
                <Mail className="text-brand-500" size={20} />
                Nouveau Message
              </h3>
              <div className="flex gap-2">
                <button
                  onClick={() => { void handleAIDraft(); }}
                  disabled={isDrafting || !composeData.clientId}
                  className="flex items-center gap-2 px-4 py-2 bg-accent-50 text-accent-600 rounded-xl text-xs font-bold uppercase tracking-widest hover:bg-accent-100 transition-all disabled:opacity-50"
                >
                  {isDrafting ? (
                    <Clock className="animate-spin" size={14} />
                  ) : (
                    <Wand2 size={14} />
                  )}
                  Aide ?? la r??daction
                </button>
                <button
                  onClick={() => setShowPreview(!showPreview)}
                  className={`flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold uppercase tracking-widest transition-all ${showPreview ? "bg-brand-900 text-white" : "bg-brand-50 text-brand-600 hover:bg-brand-100"}`}
                >
                  <Eye size={14} />
                  {showPreview ? "??diter" : "Aper??u"}
                </button>
              </div>
            </div>

            {showPreview ? (
              <div className="space-y-6 animate-fade-in">
                <div className="p-6 bg-brand-50 rounded-2xl border border-brand-100">
                  <div className="mb-4 pb-4 border-b border-brand-200">
                    <div className="text-xs font-bold text-brand-400 uppercase mb-1">
                      ??:
                    </div>
                    <div className="text-brand-900 font-medium">
                      {composeData.to || "(Non sp??cifi??)"}
                    </div>
                  </div>
                  <div className="mb-4 pb-4 border-b border-brand-200">
                    <div className="text-xs font-bold text-brand-400 uppercase mb-1">
                      Sujet:
                    </div>
                    <div className="text-brand-900 font-bold">
                      {composeData.subject || "(Sans objet)"}
                    </div>
                  </div>
                  <div className="text-brand-800 whitespace-pre-wrap leading-relaxed min-h-50">
                    {composeData.body || "(Message vide)"}
                  </div>
                </div>
                <div className="flex justify-end gap-3">
                  <button
                    onClick={() => setShowPreview(false)}
                    className="px-6 py-3 text-brand-600 font-bold text-xs uppercase tracking-widest hover:bg-brand-50 rounded-2xl"
                  >
                    Retour ?? l'??dition
                  </button>
                </div>
              </div>
            ) : (
              <form onSubmit={handleSendEmail} className="space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div>
