export default EntityModal;

/**
 * Composant FormFieldValidated - FormField avec validation int??gr??e
 * Remplace le FormField basique avec validation live
 *
 * Usage simple:
 * ```tsx
 * <FormFieldValidated
 *   label="Email"
 *   type="email"
 *   value={email}
 *   onChange={setEmail}
 *   validator={validateEmail}
 * />
 *
 * <FormFieldValidated
 *   label="SIRET"
 *   value={siret}
 *   onChange={setSiret}
 *   validator={validateSIRET}
 *   validationType="siret"
 * />
 * ```
 */

import {
  CircleAlert as AlertCircle,
  CircleCheck as CheckCircle2,
  type LucideIcon,
} from "lucide-react";
import React, { useEffect, useState } from "react";
import {
  validateAddressForm,
  validateAmount,
  validateDate,
  validateEmailForm,
  validateFrenchPostalCode,
  validateIBAN,
  validateName,
  validatePhoneForm,
  validateRequired,
  validateSIREN,
  validateSIRETForm,
  validateTVANumberForm,
  validateWebsiteForm,
  type ValidationResult,
} from "../lib/zod-schemas";

// Aliases for validator map keys
const validateFrenchPhone = validatePhoneForm;
const validateVATNumber = validateTVANumberForm;

type ValidationType =
  | "siret"
  | "siren"
  | "iban"
  | "email"
  | "postal-code"
  | "phone"
  | "vat"
  | "website"
  | "name"
  | "amount"
  | "date"
  | "required"
  | "address"
  | "none";

// Map des validateurs - accepte any pour les diff??rentes signatures de validateurs
const validatorsMap: Record<
  ValidationType,
  (value: unknown) => ValidationResult
> = {
  siret: validateSIRETForm,
  siren: validateSIREN,
  iban: validateIBAN,
  email: validateEmailForm,
  "postal-code": validateFrenchPostalCode,
  phone: validateFrenchPhone,
  vat: validateVATNumber,
  website: validateWebsiteForm,
  name: validateName,
  amount: validateAmount,
  date: validateDate,
  required: validateRequired,
  address: validateAddressForm,
  none: () => ({ valid: true }),
};

// Suggestions d'auto-d??tection sur type HTML
const htmlTypeToValidation: Record<string, ValidationType> = {
  email: "email",
  tel: "phone",
  date: "date",
  url: "website",
  number: "amount",
  text: "none",
};

const getFieldBorderClass = (hasErr: boolean, hasSuc: boolean): string => {
  if (hasErr) {
    return "border-red-500 focus:ring-red-500/10 focus:border-red-600";
  }
  if (hasSuc) {
    return "border-green-500 focus:ring-green-500/10 focus:border-green-600";
  }
  return "";
};

interface FormFieldValidatedProps {
  id?: string;
  label: string;
  description?: string;
  required?: boolean;
  /**
   * Type HTML standard ou custom pour auto-d??tection
   */
  type?:
    | "text"
    | "email"
    | "number"
    | "password"
    | "url"
    | "tel"
    | "search"
    | "date"
    | "checkbox"
    | "textarea";
  value: string | number;
  onChange: (value: string) => void;
  /**
   * Validator personnalis?? (surcharge auto-d??tection)
   */
  validator?: (value: string | number) => ValidationResult;
  /**
   * Type de validation: si fourni, surcharge auto-d??tection et validator prop
   */
  validationType?: ValidationType;
  placeholder?: string;
  icon?: LucideIcon;
  className?: string;
  inputClassName?: string;
  min?: string | number;
  max?: string | number;
  step?: string | number;
  validateOnChange?: boolean;
  validateOnBlur?: boolean;
  showErrorsImmediate?: boolean;
  showValidationIcon?: boolean;
  "aria-label"?: string;
  autoComplete?: string;
  maxLength?: number;
  error?: ValidationResult | null;
  touched?: boolean;
}

export const FormFieldValidated: React.FC<FormFieldValidatedProps> = ({
  id,
  label,
  description,
  required = false,
  type = "text",
  value,
  onChange,
  validator,
  validationType,
  placeholder,
  icon: Icon,
  className = "",
  inputClassName = "",
  min,
  max,
  step,
  validateOnChange = true,
  validateOnBlur = true,
  showErrorsImmediate = true,
  showValidationIcon = true,
  "aria-label": ariaLabel,
  maxLength,
  autoComplete: _autoComplete,
  // Propri??t??s optionnelles pour int??gration avec useFormValidation
  error: externalError,
  touched: externalTouched,
}) => {
  const isTextarea = type === "textarea";

  // D??terminer le validateur ?? utiliser
  const determineValidator = (): ((
    value: string | number,
  ) => ValidationResult) => {
    // Si validationType est fourni, utiliser ??a
    if (validationType) {
      return validatorsMap[validationType];
    }

    // Si validator personnalis?? est fourni
    if (validator) {
      return validator;
    }

    // Auto-d??tection bas??e sur type HTML
    const autoDetectedValidation = htmlTypeToValidation[type] || "none";
    return validatorsMap[autoDetectedValidation];
  };

  const finalValidator = determineValidator();

  // ??tat de validation interne (fallback si pas d'error externe)
  const [internalError, setInternalError] = useState<ValidationResult | null>(
    null,
  );
  const [internalTouched, setInternalTouched] = useState(false);

  // Validation au changement
  useEffect(() => {
    if (validateOnChange && value !== undefined) {
      const result = finalValidator(value);
      setInternalError(result);
    }
  }, [value, finalValidator, validateOnChange]);

  // D??terminer l'erreur et le statut touch?? final
  const currentError =
    externalError !== undefined ? externalError : internalError;
  const isTouched =
    externalTouched ?? internalTouched;

  // Afficher l'erreur si on a une erreur ET (soit on affiche tout de suite, soit le champ a ??t?? touch??)
  const shouldShowError =
    currentError && !currentError.valid && (showErrorsImmediate || isTouched);
  const isValid = currentError?.valid === true;

  // Handler combin?? pour onChange
  const handleChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>,
  ) => {
    const newValue = e.target.value;
    onChange(newValue);
  };

  const handleBlur = (
    e: React.FocusEvent<HTMLInputElement | HTMLTextAreaElement>,
  ) => {
    setInternalTouched(true);
    if (validateOnBlur) {
      const result = finalValidator(e.target.value);
      setInternalError(result);
    }
  };

  const fieldId = id ?? `field-${label.toLowerCase().replaceAll(/\s+/g, "-")}`;

  let describedByValue: string | undefined;
  if (shouldShowError) {
    describedByValue = `${fieldId}-error`;
  } else if (description) {
    describedByValue = `${fieldId}-description`;
  }

  const ariaAttrs = {
    "aria-required": required ? ("true" as const) : ("false" as const),
    "aria-invalid":
      !isValid && isTouched ? ("true" as const) : ("false" as const),
  };

  const hasError = shouldShowError;
  const hasSuccess = currentError && currentError.valid && value;

  return (
    <div className={`space-y-1.5 ${className}`}>
      {/* Label */}
      <div className="flex items-center justify-between gap-2">
        <label
          htmlFor={fieldId}
          className="block text-[10px] font-bold text-brand-400 dark:text-brand-500 uppercase tracking-widest"
        >
          {label}
          {required && (
            <span className="text-red-500 ml-1" aria-hidden="true">
              *
            </span>
          )}
        </label>
        {showValidationIcon && hasSuccess && (
          <CheckCircle2
            size={14}
            className="text-green-600 dark:text-green-400"
            aria-hidden="true"
          />
        )}
      </div>

      {/* Input Container */}
      <div className="relative">
        {Icon && (
          <Icon
            className="absolute left-4 top-1/2 -translate-y-1/2 text-brand-300 dark:text-brand-600 pointer-events-none"
            size={18}
            aria-hidden="true"
          />
        )}

        {isTextarea ? (
          <textarea
            id={fieldId}
            required={required}
            value={value}
            onChange={handleChange}
            onBlur={handleBlur}
            placeholder={placeholder}
            {...(_autoComplete && { autoComplete: _autoComplete })}
            {...ariaAttrs}
            aria-label={ariaLabel}
            aria-describedby={describedByValue}
            maxLength={maxLength}
            className={`w-full ${Icon ? "pl-12" : "pl-4"} p-4 bg-white dark:bg-(--input-bg) border border-(--input-border) rounded-2xl outline-none focus:ring-4 focus:ring-(--input-focus-ring) focus:border-(--input-focus-border) text-(--input-text) placeholder:text-(--input-placeholder) transition-all resize-y min-h-24 ${getFieldBorderClass(!!hasError, !!(currentError && currentError.valid && value))} ${inputClassName}`}
          />
        ) : (
          <input
            id={fieldId}
            type={type}
            required={required}
            value={value}
            onChange={handleChange}
            onBlur={handleBlur}
            placeholder={placeholder}
            {...(_autoComplete && { autoComplete: _autoComplete })}
            {...ariaAttrs}
            aria-label={ariaLabel}
            aria-describedby={describedByValue}
            min={min}
            max={max}
            step={step}
            maxLength={maxLength}
            className={`w-full ${Icon ? "pl-12" : "pl-4"} p-4 bg-white dark:bg-(--input-bg) border border-(--input-border) rounded-2xl outline-none focus:ring-4 focus:ring-(--input-focus-ring) focus:border-(--input-focus-border) text-(--input-text) placeholder:text-(--input-placeholder) transition-all ${getFieldBorderClass(!!hasError, !!(currentError && currentError.valid && value))} ${inputClassName}`}
          />
        )}

        {/* Erreur Icon */}
        {showValidationIcon && hasError && (
          <AlertCircle
            size={18}
            className="absolute right-4 top-1/2 -translate-y-1/2 text-red-600 dark:text-red-400 pointer-events-none"
            aria-hidden="true"
          />
        )}
      </div>

      {/* Description */}
      {description && (
        <p
          id={`${fieldId}-description`}
          className="text-[10px] text-brand-400 dark:text-brand-500 mt-1 font-medium italic"
        >
          {description}
        </p>
      )}

      {/* Erreur */}
      {hasError && (
        <p
          id={`${fieldId}-error`}
          className="text-[10px] text-red-600 dark:text-red-400 font-medium flex items-center gap-1"
        >
          <AlertCircle size={12} aria-hidden="true" />
          {currentError.error}
        </p>
      )}

      {/* Succ??s (optionnel) */}
      {hasSuccess && !description && (
        <p className="text-[10px] text-green-600 dark:text-green-400 font-medium flex items-center gap-1">
          <CheckCircle2 size={12} aria-hidden="true" />
          Valide !
        </p>
      )}
    </div>
  );
};

