                          className="p-2 hover:bg-green-100 dark:hover:bg-green-900 rounded text-green-600 disabled:opacity-50"
                          title="Signer num??riquement"
                          aria-label={`Signer num??riquement le document ${inv.number}`}
                        >
                          <ShieldCheck size={16} />
                        </button>
                        <button
