                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
      </div>

      {/* ?????? APER??U IMPRESSION ????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????? */}
      {previewInvoice && (
        <Suspense fallback={null}>
          <InvoicePaper
            invoice={previewInvoice}
            client={clients.find((c) => c.id === previewInvoice.clientId)}
            userProfile={userProfile}
            onClose={() => setPreviewInvoice(null)}
          />
        </Suspense>
      )}
    </div>
  );
};

