    setUserProfile(updatedProfile);
    setIsDirty(true);
    if (field === "siret") {
      setValidationErrors((prev) => ({
        ...prev,
        siret: validateSIRET(value as string),
      }));
    } else if (field === "bankAccount") {
      setValidationErrors((prev) => ({
        ...prev,
        bankAccount: validateIBAN(value as string),
      }));
    } else if (field === "email") {
