  /**
   * handleCleanData - Nettoyage des donn??es (doublons de clients, produits inutilis??s)
   * @param type 'clients' | 'products'
   */
  const handleCleanData = async (type: "clients" | "products") => {
    if (type === "clients") {
      const namesMap = new Map<string, Client>();
      const toKeep: Client[] = [];
      const duplicatesCount = { total: 0 };

      allData.clients.forEach((client) => {
        const normalized = client.name.trim().toLowerCase();
        if (namesMap.has(normalized)) {
          duplicatesCount.total++;
        } else {
          namesMap.set(normalized, client);
          toKeep.push(client);
        }
      });

      if (duplicatesCount.total === 0) {
        toast.info("Aucun client en doublon d??tect??.");
        return;
      }

      setConfirmDialog({
        isOpen: true,
        title: "Fusionner les clients en doublon ?",
        description: `Nous avons d??tect?? ${duplicatesCount.total} client(s) avec des noms identiques. Voulez-vous les fusionner ? (Seul le premier profil sera conserv??).`,
        onConfirm: () => {
          setAllData.setClients(toKeep);
          addLog(
            `${duplicatesCount.total} clients fusionn??s/nettoy??s`,
            "DATA",
            "INFO",
          );
          toast.success(`${duplicatesCount.total} clients fusionn??s`);
          setConfirmDialog({ isOpen: false, title: "", description: "" });
        },
      });
    } else if (type === "products") {
      const usedProductIds = new Set<string>();
      allData.invoices.forEach((inv) => {
        inv.items.forEach((item) => {
          if (item.id) {
            usedProductIds.add(item.id);
          }
        });
      });

      const unusedProducts = allData.products.filter(
        (p) => !usedProductIds.has(p.id),
      );

      if (unusedProducts.length === 0) {
        toast.info(
          "Tous vos produits sont actuellement utilis??s dans des factures.",
        );
        return;
      }

      setConfirmDialog({
        isOpen: true,
        title: "Supprimer les produits inutilis??s ?",
        description: `Il y a ${unusedProducts.length} produit(s) qui n'ont jamais ??t?? ajout??s ?? une facture ou un devis. Voulez-vous les supprimer ?`,
        onConfirm: () => {
          const keptProducts = allData.products.filter((p) =>
            usedProductIds.has(p.id),
          );
          setAllData.setProducts(keptProducts);
          addLog(
            `${unusedProducts.length} produits inutilis??s supprim??s`,
            "DATA",
            "INFO",
          );
          toast.success(`${unusedProducts.length} produits supprim??s`);
          setConfirmDialog({ isOpen: false, title: "", description: "" });
        },
      });
    }
  };

