export default SettingsManager;

import {
  CircleAlert as AlertCircle,
  Archive,
  Download,
  Plus,
  Truck,
  Upload,
  Wallet,
} from "lucide-react";
import React, { useMemo, useRef } from "react";
import { useEntityFilters, useEntityForm } from "../hooks/useEntity";
import { useFormValidation } from "../hooks/useFormValidation";
import { schemaToRules, SupplierSchema } from "../lib/zod-schemas";
import type { Expense, Supplier } from "../types";
import {
  AddressFields,
  ContactFields,
  SearchFilterFields,
} from "./EntityFormFields";
import EntityModal from "./EntityModal";
import { FormFieldValidated } from "./FormFieldValidated";
import { TextAreaField } from "./FormFields";

interface SupplierManagerProps {
  suppliers: Supplier[];
  setSuppliers: (suppliers: Supplier[]) => void;
  expenses: Expense[];
  onSave?: (supplier: Supplier) => void;
  onDelete?: (id: string) => void;
}

const SupplierManager: React.FC<SupplierManagerProps> = ({
  suppliers,
  setSuppliers,
  expenses,
  onSave,
  onDelete,
}) => {
  const form = useEntityForm<Supplier>();
  const filters = useEntityFilters(
    suppliers as unknown as Record<string, unknown>[],
    {
      searchField: "name",
      hasArchive: true,
      archiveField: "archived",
    },
  );
  const fileInputRef = useRef<HTMLInputElement>(null);

  const {
    data: validatedData,
    errors: validationErrors,
    touched: touchedFields,
    handleChange: handleFormChange,
    validate: validateAll,
  } = useFormValidation(
    form.formData ?? ({} as Supplier),
    schemaToRules(SupplierSchema),
    {
      validateOnChange: true,
    },
  );

  // Stats: spending by supplier
  const getSupplierStats = (supplierId: unknown) => {
    if (typeof supplierId !== "string") {
      return { totalSpent: 0, count: 0 };
    }
    const supplierExpenses = expenses.filter(
      (exp) => exp.supplierId === supplierId,
    );
    const totalSpent = supplierExpenses.reduce(
      (sum, exp) => sum + exp.amount,
      0,
    );
    return { totalSpent, count: supplierExpenses.length };
  };

  const globalStats = useMemo(() => {
    const activeSuppliers = suppliers.filter((s) => !s.archived);
    const totalExpenses = expenses.reduce((sum, exp) => sum + exp.amount, 0);
    return {
      count: activeSuppliers.length,
      totalExpenses,
      archivedCount: suppliers.length - activeSuppliers.length,
    };
  }, [suppliers, expenses]);

  const processedSuppliers = useMemo(() => {
    return (filters.filteredEntities as unknown as Supplier[]).sort((a, b) =>
      a.name.localeCompare(b.name),
    );
  }, [filters.filteredEntities]);

  // Form handlers
  const handleSubmit = async (e?: React.SyntheticEvent<HTMLFormElement>) => {
    e?.preventDefault();

    // Valider avant de soumettre
    if (!validateAll()) {
      return;
    }

    if (form.isEditing && form.editingId) {
      const original = suppliers.find((s) => s.id === form.editingId);
      const updated = { ...original, ...validatedData } as Supplier;
      setSuppliers(
        suppliers.map((s) => (s.id === form.editingId ? updated : s)),
      );
      onSave?.(updated);
    } else {
      const newSupplier: Supplier = {
        ...validatedData,
        id: Date.now().toString(),
        createdAt: new Date().toISOString(),
        archived: false,
      } as Supplier;
      setSuppliers([...suppliers, newSupplier]);
      onSave?.(newSupplier);
    }
    form.closePanel();
  };

  const handleDelete = async () => {
    if (!form.editingId) {
      return;
    }
    setSuppliers(suppliers.filter((s) => s.id !== form.editingId));
    onDelete?.(form.editingId);
    form.closePanel();
  };

  const toggleArchive = (id: string) => {
    const supplier = suppliers.find((s) => s.id === id);
    if (supplier) {
      const updated = { ...supplier, archived: !supplier.archived };
      setSuppliers(suppliers.map((s) => (s.id === id ? updated : s)));
      onSave?.(updated);
    }
  };

  const exportCSV = () => {
    const headers = [
      "Nom",
      "Contact",
      "Cat??gorie",
      "Email",
      "T??l??phone",
      "Adresse",
      "SIRET",
      "TVA",
      "Site Web",
      "Conditions Paiement",
      "Notes",
      "Total D??pens??",
      "Date Cr??ation",
      "Statut",
    ];
    const rows = processedSuppliers.map((s) => {
      const supplier = s as Supplier;
      const stats = getSupplierStats(supplier.id);
      const contactName: string = supplier.contactName ?? "";
      const category: string = supplier.category ?? "";
      const email: string = supplier.email ?? "";
      const phone: string = supplier.phone ?? "";
      const address: string = supplier.address?.replaceAll("\n", " ") ?? "";
      const siret: string = supplier.siret ?? "";
      const tvaNumber: string = supplier.tvaNumber ?? "";
      const website: string = supplier.website ?? "";
      const paymentTerms: string = supplier.paymentTerms ?? "";
      const notes: string = supplier.notes?.replaceAll("\n", " ") ?? "";
      const createdAt: string = supplier.createdAt ?? "";
      return [
        '"' + s.name + '"',
        '"' + contactName + '"',
        '"' + category + '"',
        '"' + email + '"',
        '"' + phone + '"',
        '"' + address + '"',
        '"' + siret + '"',
        '"' + tvaNumber + '"',
        '"' + website + '"',
        '"' + paymentTerms + '"',
        '"' + notes + '"',
        stats.totalSpent.toFixed(2),
        '"' + createdAt + '"',
        s.archived ? '"Archiv??"' : '"Actif"',
      ].join(",");
    });
    const csv = [headers.join(","), ...rows].join("\n");
    const link = document.createElement("a");
    link.href = `data:text/csv;charset=utf-8,${encodeURIComponent(csv)}`;
    link.download = `fournisseurs_${filters.showArchived ? "archives" : "actifs"}_${new Date().toISOString().split("T")[0]}.csv`;
    document.body.appendChild(link);
    link.click();
    link.remove();
  };

  const handleImportCSV = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) {
      return;
    }
    const text = await file.text();
    const lines = text.split("\n");
    const newSuppliers: Supplier[] = [];

    for (let i = 1; i < lines.length; i++) {
      const line = lines[i].trim();
      if (!line) {
        continue;
      }
      const parts = line
        .split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/)
        .map((p) => p.replaceAll('"', ""));
      if (parts.length >= 1) {
        newSuppliers.push({
          id: `${Date.now()}_${i}`,
          name: parts[0],
          contactName: parts[1],
          category: parts[2],
          email: parts[3],
          phone: parts[4],
          address: parts[5],
          siret: parts[6],
          tvaNumber: parts[7],
          website: parts[8],
          paymentTerms: parts[9],
          notes: parts[10],
          archived: false,
          createdAt: new Date().toISOString(),
        });
      }
    }

    if (newSuppliers.length > 0) {
      setSuppliers([...suppliers, ...newSuppliers]);
      if (fileInputRef.current) {
        fileInputRef.current.value = "";
      }
    }
  };

  return (
    <div className="space-y-8 max-w-7xl mx-auto pb-10">
      {/* Header */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
        <div>
          <h2 className="text-3xl font-bold text-brand-900 dark:text-white font-display">
            Gestion Fournisseurs
          </h2>
          <p className="text-brand-500 dark:text-brand-400 mt-1">
            G??rez vos partenaires et suivez vos achats.
          </p>
        </div>

        <div className="flex flex-wrap gap-3">
          <div className="bg-white dark:bg-brand-900 p-1.5 rounded-2xl border border-brand-200 dark:border-brand-800 flex gap-1">
            <button
              onClick={() => filters.setShowArchived(false)}
              className={`px-6 py-2 rounded-xl text-sm font-bold transition-all ${
                filters.showArchived
                  ? "bg-brand-900 text-white dark:bg-white dark:text-brand-900"
                  : "text-brand-500"
              }`}
            >
              Actifs
            </button>
            <button
              onClick={() => filters.setShowArchived(true)}
              className={`px-6 py-2 rounded-xl text-sm font-bold transition-all ${
                filters.showArchived
                  ? "bg-brand-900 text-white dark:bg-white dark:text-brand-900"
                  : "text-brand-500"
              }`}
            >
              Archiv??s
            </button>
          </div>

          <label className="btn-secondary px-4 py-2.5 cursor-pointer">
            <Upload size={18} />
            <span className="hidden sm:inline">Import</span>
            <input
              ref={fileInputRef}
              type="file"
              accept=".csv"
              className="hidden"
              onChange={(e) => {
                void handleImportCSV(e);
              }}
            />
          </label>
          <button onClick={exportCSV} className="btn-secondary px-4 py-2.5">
            <Download size={18} />
            <span className="hidden sm:inline">Export</span>
          </button>
          <button
            onClick={() => form.openCreate()}
            className="btn-primary px-6 py-2.5"
          >
            <Plus size={18} />
            Nouveau
          </button>
        </div>
      </div>

      {/* Stats */}
      <div className="bento-grid">
        <div className="bento-item">
          <div className="p-3 bg-brand-100 dark:bg-brand-800 rounded-2xl text-brand-600 dark:text-brand-300 mb-4">
            <Truck size={24} />
          </div>
          <h3 className="text-2xl font-bold text-brand-900 dark:text-white">
            {globalStats.count}
          </h3>
          <p className="text-xs text-brand-500 dark:text-brand-400 mt-1">
            Fournisseurs Actifs
          </p>
        </div>
        <div className="bento-item">
          <div className="p-3 bg-accent-100 dark:bg-accent-900/30 rounded-2xl text-accent-600 dark:text-accent-400 mb-4">
            <Wallet size={24} />
          </div>
          <h3 className="text-2xl font-bold text-accent-600 dark:text-accent-400">
            {globalStats.totalExpenses.toLocaleString("fr-FR", {
              style: "currency",
              currency: "EUR",
            })}
          </h3>
          <p className="text-xs text-brand-500 dark:text-brand-400 mt-1">
            Total D??pens??
          </p>
        </div>
        <div className="bento-item">
          <div className="p-3 bg-brand-100 dark:bg-brand-800 rounded-2xl text-brand-600 dark:text-brand-300 mb-4">
            <Archive size={24} />
          </div>
          <h3 className="text-2xl font-bold text-brand-900 dark:text-white">
            {globalStats.archivedCount}
          </h3>
          <p className="text-xs text-brand-500 dark:text-brand-400 mt-1">
            Archiv??s
          </p>
        </div>
      </div>

      {/* Search */}
      <SearchFilterFields
        searchTerm={filters.searchTerm}
        showArchived={filters.showArchived}
        onSearchChange={filters.setSearchTerm}
        onShowArchivedChange={filters.setShowArchived}
        placeholder="Rechercher par nom, email, SIRET..."
      />

      {/* Supplier List */}
      <div className="space-y-3">
        {processedSuppliers.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-12 text-center">
            <AlertCircle
              size={48}
              className="text-brand-300 dark:text-brand-700 mb-4"
            />
            <h3 className="text-lg font-semibold text-brand-900 dark:text-white">
              Aucun fournisseur trouv??
            </h3>
          </div>
        ) : (
          processedSuppliers.map((supplier) => {
            const stats = getSupplierStats(supplier.id);
            return (
              <div
                key={(supplier as Supplier).id}
                className="p-4 bg-white dark:bg-slate-800 rounded-lg border border-brand-200 dark:border-slate-700 hover:shadow-md transition-all flex justify-between items-center group"
              >
                <button
                  onClick={() => form.openEdit(supplier as Supplier)}
                  aria-label={`Modifier le fournisseur ${supplier.name}`}
                  className="flex-1 text-left rounded-lg p-2 -m-2 hover:bg-brand-50 dark:hover:bg-brand-900/50 transition-colors focus:outline-none focus-visible:ring-2 focus-visible:ring-brand-500"
                >
                  <div>
                    <h4 className="font-semibold text-brand-900 dark:text-white">
                      {supplier.name}
                    </h4>
                    <p className="text-sm text-brand-500 dark:text-brand-400">
                      {supplier.category ?? "???"} ??? {supplier.email}
                    </p>
                    <p className="text-xs text-brand-400 dark:text-brand-500 mt-1">
                      Total d??pens??:{" "}
                      <span className="font-bold">
                        {stats.totalSpent.toLocaleString("fr-FR", {
                          style: "currency",
                          currency: "EUR",
                        })}
                      </span>
                    </p>
                  </div>
                </button>
                <div className="flex gap-2">
                  <button
                    onClick={() => toggleArchive((supplier as Supplier).id)}
                    aria-label={
                      supplier.archived
                        ? `Restaurer le fournisseur ${supplier.name}`
                        : `Archiver le fournisseur ${supplier.name}`
                    }
                    className={`p-2 rounded-lg transition-colors focus:outline-none focus-visible:ring-2 focus-visible:ring-amber-500 ${supplier.archived ? "bg-amber-50 text-amber-600" : "hover:bg-brand-50 text-brand-400"}`}
                  >
                    <Archive size={18} aria-hidden="true" />
                  </button>
                </div>
              </div>
            );
          })
        )}
      </div>

      {/* Modal Form */}
      <EntityModal
        isOpen={form.isPanelOpen}
        title={
          form.isEditing ? "Modifier le fournisseur" : "Nouveau fournisseur"
        }
        isEditing={form.isEditing}
        onClose={form.closePanel}
        onSave={() => {
          void handleSubmit();
        }}
        onDelete={handleDelete}
        showDeleteButton={form.isEditing}
      >
        <div className="space-y-6">
          <ContactFields
            name={validatedData.name || ""}
            email={validatedData.email ?? ""}
            phone={validatedData.phone ?? ""}
            onNameChange={(val) => handleFormChange("name")(val)}
            onEmailChange={(val) => handleFormChange("email")(val)}
            onPhoneChange={(val) => handleFormChange("phone")(val)}
            contactNameLabel="Nom du fournisseur"
            required={true}
            validationErrors={validationErrors}
            touchedFields={touchedFields}
          />

          <div className="space-y-4">
            <h4 className="text-xs font-bold text-brand-600 dark:text-brand-300 uppercase tracking-wider">
              Identit?? Professionnelle & Liens
            </h4>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <FormFieldValidated
                label="N?? TVA (optionnel)"
                value={validatedData.tvaNumber ?? ""}
                onChange={(val) => handleFormChange("tvaNumber")(val)}
                validationType="vat"
                error={validationErrors.tvaNumber}
                touched={touchedFields.tvaNumber}
              />
              <FormFieldValidated
                label="Site Web"
                value={validatedData.website ?? ""}
                onChange={(val) => handleFormChange("website")(val)}
                validationType="website"
                error={validationErrors.website}
                touched={touchedFields.website}
              />
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <FormFieldValidated
                label="IBAN"
                value={validatedData.iban ?? ""}
                onChange={(val) => handleFormChange("iban")(val)}
                validationType="iban"
                placeholder="FR14..."
                error={validationErrors.iban}
                touched={touchedFields.iban}
              />
              <FormFieldValidated
                label="Cat??gorie"
                value={validatedData.category ?? ""}
                onChange={(val) => handleFormChange("category")(val)}
                type="text"
                validationType="name"
                placeholder="Ex: Mat??riel, Logiciel..."
                error={validationErrors.category}
                touched={touchedFields.category}
              />
            </div>
          </div>

          <div className="space-y-4">
            <h4 className="text-xs font-bold text-brand-600 dark:text-brand-300 uppercase tracking-wider">
              Localisation & Notes
            </h4>
            <AddressFields
              address={validatedData.address ?? ""}
              postalCode={""}
              city={""}
              onAddressChange={(val) => handleFormChange("address")(val)}
              onPostalCodeChange={() => undefined}
              onCityChange={() => undefined}
              showPostalCity={false}
              validationErrors={validationErrors}
              touchedFields={touchedFields}
            />
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <FormFieldValidated
                label="D??lai de paiement (jours)"
                value={validatedData.paymentTerms ?? "30"}
                onChange={(val) => handleFormChange("paymentTerms")(val)}
                type="number"
                validationType="amount"
                error={validationErrors.paymentTerms}
                touched={touchedFields.paymentTerms}
              />
              <FormFieldValidated
                label="SIRET"
                value={validatedData.siret ?? ""}
                onChange={(val) => handleFormChange("siret")(val)}
                validationType="siret"
                error={validationErrors.siret}
                touched={touchedFields.siret}
              />
            </div>
            <TextAreaField
              label="Notes"
              value={validatedData.notes ?? ""}
              onChange={(val) => handleFormChange("notes")(val)}
              rows={3}
            />
          </div>
        </div>
      </EntityModal>
    </div>
  );
};

export default SupplierManager;

/**
 * VATDashboardManager ??? Tableau de bord TVA Franchise
 * ??????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????
 * Pour les micro-entrepreneurs en franchise en base de TVA (art. 293 B CGI).
 * Suivi mensuel du CA, seuils TVA, et simulation "passage au r??gime TVA".
 */

import Decimal from 'decimal.js';
import {
  CircleAlert as AlertCircle,
  ArrowRight,
  BadgeCheck,
  ChartColumnIncreasing as BarChart3,
  Calculator,
  ChevronDown,
  Euro,
  TrendingUp,
  TriangleAlert,
} from 'lucide-react';
import React, { useMemo, useState } from 'react';
import {
  Area,
  AreaChart,
  CartesianGrid,
  ReferenceLine,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from 'recharts';
import { getThresholds } from '../lib/fiscalCalculations';
import { InvoiceStatus, type Invoice, type UserProfile } from '../types';

interface VATDashboardManagerProps {
  invoices: Invoice[];
  userProfile: UserProfile;
}

// ????????? Constantes TVA r??gime r??el ???????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????
const VAT_RATES = { NORMAL: 20, REDUCED_1: 10, REDUCED_2: 5.5, SUPER_REDUCED: 2.1 };

const MONTH_LABELS = [
  'Jan',
  'F??v',
  'Mar',
  'Avr',
  'Mai',
  'Juin',
  'Juil',
  'Ao??t',
  'Sep',
  'Oct',
  'Nov',
  'D??c',
];

// ????????? Composant principal ???????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????

const VATDashboardManager: React.FC<VATDashboardManagerProps> = ({ invoices, userProfile }) => {
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());
  const [simulationAmount, setSimulationAmount] = useState<string>('');
  const [simulationRate, setSimulationRate] = useState<number>(20);

  const activityType = userProfile.activityType ?? 'SERVICE_BNC';
  const thresholds = getThresholds(activityType);
  const isVatExempt = userProfile.isVatExempt ?? true;

  // ?????? Donn??es annuelles ????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????
  const { yearTotal, cumulativeData } = useMemo(() => {
    const monthly = Array.from({ length: 12 }, (_, i) => ({ month: i, revenue: 0, count: 0 }));

    invoices
      .filter((inv) => {
        const year = new Date(inv.date).getFullYear();
        return (
          year === selectedYear &&
          inv.status === InvoiceStatus.PAID &&
          (inv.type === 'invoice' || inv.type === 'deposit_invoice')
        );
      })
      .forEach((inv) => {
        const m = new Date(inv.date).getMonth();
        monthly[m].revenue += inv.total;
        monthly[m].count += 1;
      });

    let cumul = 0;
    const cumData = monthly.map((m) => {
      cumul += m.revenue;
      return {
        name: MONTH_LABELS[m.month],
        CA: parseFloat(m.revenue.toFixed(2)),
        Cumul??: parseFloat(cumul.toFixed(2)),
        count: m.count,
      };
    });

    return {
      monthlyData: cumData,
      yearTotal: parseFloat(cumul.toFixed(2)),
      cumulativeData: cumData,
    };
  }, [invoices, selectedYear]);

  // ?????? Statut seuil ????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????
  const tvaStatus = useMemo(() => {
    const ratio =
      Number.isFinite(thresholds.tva) && thresholds.tva > 0 ? yearTotal / thresholds.tva : 0;
    const ratioTolerance =
      Number.isFinite(thresholds.tvaTolerance) && thresholds.tvaTolerance > 0
        ? yearTotal / thresholds.tvaTolerance
        : 0;
    const remaining = Math.max(0, thresholds.tva - yearTotal);
    const progressPercent = Math.min(100, Math.round(ratio * 100));

    return {
      ratio,
      ratioTolerance,
      remaining,
      progressPercent,
      isExceeded: yearTotal > thresholds.tva,
      isInToleranceBand: yearTotal > thresholds.tva && yearTotal <= thresholds.tvaTolerance,
      isAboveToleranceBand: yearTotal > thresholds.tvaTolerance,
      percentLabel: `${progressPercent}%`,
    };
  }, [yearTotal, thresholds]);

  // ?????? Simulation TVA ??????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????
  const simulation = useMemo(() => {
    const amount = parseFloat(simulationAmount) || 0;
    if (amount <= 0) {
      return null;
    }
    const vatD = new Decimal(amount)
      .times(new Decimal(simulationRate))
      .dividedBy(100)
      .toDecimalPlaces(2);
    const htD = new Decimal(amount).dividedBy(1 + simulationRate / 100).toDecimalPlaces(2);
    return {
      ht: htD.toNumber(),
      vat: vatD.toNumber(),
      ttc: amount,
      htAgainstThreshold: htD.toNumber(), // CA pris en compte = HT si assujetti
    };
  }, [simulationAmount, simulationRate]);

  // ?????? Ann??es disponibles ?????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????
  const availableYears = useMemo(() => {
    const years = new Set(invoices.map((inv) => new Date(inv.date).getFullYear()));
    years.add(new Date().getFullYear());
    return Array.from(years).sort((a, b) => b - a);
  }, [invoices]);

  // ?????? Barre de progression ???????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????????
  let progressState: 'critical' | 'exceeded' | 'warning' | 'normal' = 'normal';
  if (tvaStatus.isAboveToleranceBand) progressState = 'critical';
  else if (tvaStatus.isExceeded) progressState = 'exceeded';
  else if (tvaStatus.ratio >= 0.85) progressState = 'warning';

  const thresholdPercent = (thresholds.tva / thresholds.tvaTolerance) * 100;

  let vatBadgeClass = 'bg-brand-100 text-brand-700';
  if (tvaStatus.isAboveToleranceBand) vatBadgeClass = 'bg-red-100 text-red-700';
  else if (tvaStatus.isExceeded) vatBadgeClass = 'bg-amber-100 text-amber-700';
  else if (isVatExempt) vatBadgeClass = 'bg-accent-100 text-accent-700';

  let vatBadgeLabel = 'R??gime TVA';
  if (tvaStatus.isAboveToleranceBand) vatBadgeLabel = '??? Tol??rance d??pass??e';
  else if (tvaStatus.isExceeded) vatBadgeLabel = '??? Seuil d??pass??';
  else if (isVatExempt) vatBadgeLabel = 'Franchise active';

  return (
    <div className="space-y-6 animate-fade-in">
      {/* En-t??te */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-brand-900 dark:text-brand-50 font-display tracking-tight">
            Tableau de bord TVA
          </h2>
          <p className="text-sm text-brand-500 dark:text-brand-400 mt-1">
            {isVatExempt
              ? 'Franchise en base ??? art. 293 B du CGI'
              : 'R??gime TVA r??el simplifi?? actif'}
          </p>
        </div>
        <div className="relative">
          <select
            value={selectedYear}
            onChange={(e) => setSelectedYear(Number(e.target.value))}
            className="appearance-none pl-4 pr-8 py-2.5 border border-brand-100 dark:border-brand-700 rounded-2xl text-sm font-bold text-brand-700 dark:text-brand-200 bg-white dark:bg-brand-900 focus:outline-none focus:ring-2 focus:ring-brand-200"
            aria-label="S??lectionner l'ann??e"
          >
            {availableYears.map((y) => (
              <option key={y} value={y}>
                {y}
              </option>
            ))}
          </select>
          <ChevronDown
            size={14}
            className="absolute right-3 top-1/2 -translate-y-1/2 text-brand-400 pointer-events-none"
          />
        </div>
      </div>

      {/* Alerte si d??passement */}
      {tvaStatus.isAboveToleranceBand && (
        <div
          role="alert"
          className="flex items-start gap-3 p-4 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-900/30 rounded-2xl text-sm text-red-700 dark:text-red-300"
        >
          <TriangleAlert size={16} className="shrink-0 mt-0.5" />
          <div>
            <strong>Seuil de tol??rance d??pass??.</strong> Vous ??tes soumis ?? la TVA d??s le 1er jour
            du mois suivant le d??passement ({thresholds.tvaTolerance.toLocaleString('fr-FR')} ???).
            Contactez un expert-comptable.
          </div>
        </div>
      )}
      {tvaStatus.isInToleranceBand && (
        <div
          role="alert"
          className="flex items-start gap-3 p-4 bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-900/30 rounded-2xl text-sm text-amber-700 dark:text-amber-300"
        >
          <AlertCircle size={16} className="shrink-0 mt-0.5" />
          <div>
            Vous avez d??pass?? le seuil de franchise ({thresholds.tva.toLocaleString('fr-FR')} ???)
            mais restez dans la zone de tol??rance jusqu'??{' '}
            {thresholds.tvaTolerance.toLocaleString('fr-FR')} ???. Vous pouvez continuer sans TVA
            cette ann??e, mais devrez l'appliquer l'ann??e suivante si le cumul reste sup??rieur.
          </div>
        </div>
      )}

      {/* KPIs */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="card-modern p-5">
          <div className="flex items-center gap-2 mb-2">
            <Euro size={14} className="text-brand-400" />
            <p className="text-[10px] font-bold text-brand-400 uppercase tracking-widest">
              CA {selectedYear}
            </p>
          </div>
          <p className="text-2xl font-bold text-brand-900 dark:text-brand-50 font-display">
            {yearTotal.toLocaleString('fr-FR', { minimumFractionDigits: 2 })} ???
          </p>
        </div>
        <div className="card-modern p-5">
          <div className="flex items-center gap-2 mb-2">
            <BarChart3 size={14} className="text-brand-400" />
            <p className="text-[10px] font-bold text-brand-400 uppercase tracking-widest">
              Seuil franchise
            </p>
          </div>
          <p className="text-2xl font-bold text-brand-900 dark:text-brand-50 font-display">
            {thresholds.tva.toLocaleString('fr-FR')} ???
          </p>
        </div>
        <div className="card-modern p-5">
          <div className="flex items-center gap-2 mb-2">
            <TrendingUp
              size={14}
              className={tvaStatus.isExceeded ? 'text-red-400' : 'text-accent-500'}
            />
            <p className="text-[10px] font-bold text-brand-400 uppercase tracking-widest">
              Utilisation
            </p>
          </div>
          <p
            className={`text-2xl font-bold font-display ${tvaStatus.isExceeded ? 'text-red-600 dark:text-red-400' : 'text-brand-900 dark:text-brand-50'}`}
          >
            {tvaStatus.percentLabel}
          </p>
        </div>
        <div className="card-modern p-5">
          <div className="flex items-center gap-2 mb-2">
            <BadgeCheck
              size={14}
              className={tvaStatus.isExceeded ? 'text-red-400' : 'text-accent-500'}
            />
            <p className="text-[10px] font-bold text-brand-400 uppercase tracking-widest">
              Reste disponible
            </p>
          </div>
          <p
            className={`text-2xl font-bold font-display ${tvaStatus.isExceeded ? 'text-red-600 dark:text-red-400' : 'text-accent-600 dark:text-accent-400'}`}
          >
            {tvaStatus.remaining.toLocaleString('fr-FR', { minimumFractionDigits: 2 })} ???
          </p>
        </div>
      </div>

      {/* Barre de progression seuil TVA */}
      <div className="card-modern p-6">
        <div className="flex items-center justify-between mb-4">
          <h3 className="font-bold text-brand-800 dark:text-brand-200 text-sm">
            Progression vers le seuil TVA
          </h3>
          <span
            className={`text-[10px] font-bold uppercase tracking-wider px-2.5 py-1 rounded-full ${vatBadgeClass}`}
          >
            {vatBadgeLabel}
          </span>
        </div>

        <div className="relative h-6 bg-brand-100 dark:bg-brand-800 rounded-full overflow-hidden">
          {/* Progression CA ??? ??l??ment natif : pas d'inline style, s??mantique ARIA int??gr??e */}
          <progress
            value={tvaStatus.progressPercent}
            max={100}
            data-state={progressState}
            className="vat-progress-bar absolute inset-0 w-full h-full"
            aria-label={`${tvaStatus.progressPercent}% du seuil TVA atteint`}
          />
          {/* Marqueur seuil initial */}
          <div
            className={`absolute top-0 h-full w-0.5 bg-amber-500/50 left-[${thresholdPercent}%]`}
          />
        </div>

        <div className="flex justify-between mt-2 text-[10px] text-brand-400 font-medium">
          <span>0 ???</span>
          <span className="text-amber-600 font-bold">
            Franchise : {thresholds.tva.toLocaleString('fr-FR')} ???
          </span>
          <span className="text-red-500 font-bold">
            Tol??rance : {thresholds.tvaTolerance.toLocaleString('fr-FR')} ???
          </span>
        </div>
      </div>

      {/* Graphique CA mensuel + cumul?? */}
      <div className="card-modern p-6">
        <h3 className="font-bold text-brand-800 dark:text-brand-200 text-sm mb-5">
          CA mensuel et cumul?? ??? {selectedYear}
        </h3>
        <ResponsiveContainer width="100%" height={260}>
          <AreaChart data={cumulativeData} margin={{ top: 5, right: 10, left: -20, bottom: 0 }}>
            <defs>
              <linearGradient id="grad-ca" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="#0f172a" stopOpacity={0.15} />
                <stop offset="95%" stopColor="#0f172a" stopOpacity={0} />
              </linearGradient>
              <linearGradient id="grad-cumul" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="#22c55e" stopOpacity={0.2} />
                <stop offset="95%" stopColor="#22c55e" stopOpacity={0} />
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" vertical={false} />
            <XAxis dataKey="name" tick={{ fontSize: 10 }} tickLine={false} axisLine={false} />
            <YAxis
              tick={{ fontSize: 10 }}
              tickLine={false}
              axisLine={false}
              tickFormatter={(v) => `${(v / 1000).toFixed(0)}k`}
            />
