/**
 * Base de donn??es IndexedDB centralis??e avec Dexie
 * Gestion compl??te de la persistance locale pour la PWA
 *
 * Architecture :
 * - Sch??ma versionn??e pour migrer sans perte de donn??es
 * - Tables index??es pour optimiser les requ??tes
 * - Relations entre entit??s (Invoices ??? Clients, Items, etc.)
 * - Support du mode offline-first
 */

import Dexie, { type Table } from 'dexie';
import type {
  CalendarEvent,
  ChatMessage,
  Client,
  Email,
  EmailTemplate,
  Expense,
  Invoice,
  InvoiceItem,
  Product,
  Supplier,
  UserProfile,
} from '../types';

/**
 * S??quence de num??rotation continue pour les documents
 * Garantit l'unicit?? et la continuit?? l??gale en France
 *
 * La cl?? primaire est `type`. Le champ `year` permet de d??tecter
 * le passage d'ann??e et de r??initialiser le compteur automatiquement
 * (ex: passage de 2026 ?? 2027 ??? repart ?? 001).
 *
 * Ref l??gale : Art. 289-I-5?? CGI ??? s??quence chronologique continue
 */
export interface InvoiceNumberSequence {
  type: 'invoice' | 'quote' | 'order' | 'credit_note' | 'deposit_invoice';
  year: number; // Ann??e en cours de la s??quence (reset si changement d'ann??e)
  currentNumber: number; // Dernier num??ro utilis?? pour (type, year)
  lastUsedAt: string; // ISO timestamp pour audit
}

/**
 * Classe principale de la base de donn??es IndexedDB
 * Initialise le sch??ma et g??re la persistance des donn??es
 */
class InvoiceDB extends Dexie {
  // D??claration des tables
  invoices!: Table<Invoice>;
  invoiceItems!: Table<InvoiceItem>;
  clients!: Table<Client>;
  suppliers!: Table<Supplier>;
  products!: Table<Product>;
  expenses!: Table<Expense>;
  emails!: Table<Email>;
  emailTemplates!: Table<EmailTemplate>;
  calendarEvents!: Table<CalendarEvent>;
  userProfile!: Table<UserProfile>;
  chatMessages!: Table<ChatMessage>;
  invoiceNumberSequences!: Table<InvoiceNumberSequence>;

  constructor() {
    super('MicroGestionFacile');

    this.version(1).stores({
      // Sch??ma initial - v1
      // Format : { tableName: 'primaryKey, index1, index2, ...' }
      invoices: '&id, number, clientId, date, status, eInvoiceStatus',
      invoiceItems: '&id, invoiceId', // Relation avec invoices
      clients: '&id, name, email, archived',
      suppliers: '&id, name, email, archived',
      products: '&id, name, category, archived',
      expenses: '&id, supplierId, date, category',
      emails: '&id, relatedId, type, status, sentAt',
      emailTemplates: '&id, type, name',
      calendarEvents: '&id, clientId, invoiceId, start, type',
      userProfile: '&id', // Un seul profil utilisateur
      chatMessages: '&id, timestamp, role',
    });

    // Migration v2 - Ajout de la table de s??quences pour num??rotation continue
    this.version(2)
      .stores({
        invoices: '&id, number, clientId, date, status, eInvoiceStatus',
        invoiceItems: '&id, invoiceId',
        clients: '&id, name, email, archived',
        suppliers: '&id, name, email, archived',
        products: '&id, name, category, archived',
        expenses: '&id, supplierId, date, category',
        emails: '&id, relatedId, type, status, sentAt',
        emailTemplates: '&id, type, name',
        calendarEvents: '&id, clientId, invoiceId, start, type',
        userProfile: '&id',
        chatMessages: '&id, timestamp, role',
        invoiceNumberSequences: '&type', // 'invoice', 'quote', 'order', 'credit_note'
      })
      .upgrade(async (tx) => {
        // Initialise les s??quences ?? partir des num??ros existants
        const invoices = (await tx.table('invoices').toArray()) as Invoice[];
        const sequences: Record<string, InvoiceNumberSequence> = {};

        // Extrait le dernier num??ro utilis?? pour chaque type
        for (const doc of invoices) {
          const type = (doc.type || 'invoice') as 'invoice' | 'quote' | 'order' | 'credit_note';
          const match = doc.number.match(/(\d+)$/); // Extrait le dernier nombre
          const num = match ? parseInt(match[1], 10) : 0;

          if (!sequences[type] || sequences[type].currentNumber < num) {
            // year sera ajout?? par la migration v3 ; on caste pour compatibilit??
            sequences[type] = {
              type,
              year: 0, // Valeur temporaire ??? mise ?? jour par la migration v3
              currentNumber: num,
              lastUsedAt: new Date().toISOString(),
            };
          }
        }

        // Ins??re les s??quences initialis??es (ou d??faut si aucun doc)
        const docTypes: Array<'invoice' | 'quote' | 'order' | 'credit_note'> = [
          'invoice',
          'quote',
          'order',
          'credit_note',
        ];
        for (const type of docTypes) {
          if (!sequences[type]) {
            sequences[type] = {
              type,
              year: 0, // Valeur temporaire ??? mise ?? jour par la migration v3
              currentNumber: 0,
              lastUsedAt: new Date().toISOString(),
            };
          }
        }

        await tx.table('invoiceNumberSequences').bulkPut(Object.values(sequences));
      });

    // Migration v3 ??? Ajout du champ `year` sur les s??quences existantes
    // Art. 289-I-5?? CGI : la num??rotation doit ??tre remise ?? 1 chaque ann??e
    this.version(3)
      .stores({
        // Sch??ma identique ?? v2 ??? aucun index suppl??mentaire requis
        invoices: '&id, number, clientId, date, status, eInvoiceStatus',
        invoiceItems: '&id, invoiceId',
        clients: '&id, name, email, archived',
        suppliers: '&id, name, email, archived',
        products: '&id, name, category, archived',
        expenses: '&id, supplierId, date, category',
        emails: '&id, relatedId, type, status, sentAt',
        emailTemplates: '&id, type, name',
        calendarEvents: '&id, clientId, invoiceId, start, type',
        userProfile: '&id',
        chatMessages: '&id, timestamp, role',
        invoiceNumberSequences: '&type',
      })
      .upgrade(async (tx) => {
        // Ajoute le champ `year` aux s??quences qui ne l'ont pas encore
        const sequences = await tx.table('invoiceNumberSequences').toArray();
        for (const seq of sequences) {
          if (seq.year === undefined) {
            // On d??duit l'ann??e depuis lastUsedAt ; ?? d??faut l'ann??e courante
            const year = seq.lastUsedAt
              ? new Date(seq.lastUsedAt).getFullYear()
              : new Date().getFullYear();
            await tx.table('invoiceNumberSequences').put({ ...seq, year });
          }
        }
      });

    // Migration v4 ??? Ajout de l'index `updatedAt` pour la r??solution de conflits offline
    // Strat??gie LWW (Last-Write-Wins) : on compare updatedAt lors du merge Firestore ??? IndexedDB
    // Les enregistrements sans updatedAt sont r??troactivement initialis??s depuis date/createdAt
    this.version(4)
      .stores({
        invoices: '&id, number, clientId, date, status, eInvoiceStatus, updatedAt',
        invoiceItems: '&id, invoiceId',
        clients: '&id, name, email, archived, updatedAt',
        suppliers: '&id, name, email, archived, updatedAt',
        products: '&id, name, category, archived, updatedAt',
        expenses: '&id, supplierId, date, category, updatedAt',
        emails: '&id, relatedId, type, status, sentAt',
        emailTemplates: '&id, type, name',
        calendarEvents: '&id, clientId, invoiceId, start, type',
        userProfile: '&id',
        chatMessages: '&id, timestamp, role',
        invoiceNumberSequences: '&type',
      })
      .upgrade(async (tx) => {
        const now = new Date().toISOString();

        // Backfill invoices : utilise `date` (champ obligatoire) comme proxy
        const invoices = await tx.table('invoices').toArray();
        for (const doc of invoices) {
          if (doc.updatedAt === undefined) {
            await tx.table('invoices').put({ ...doc, updatedAt: doc.date ?? now });
          }
        }

        // Backfill clients
        const clients = await tx.table('clients').toArray();
        for (const client of clients) {
          if (client.updatedAt === undefined) {
            await tx.table('clients').put({ ...client, updatedAt: client.createdAt ?? now });
          }
        }

        // Backfill suppliers
        const suppliers = await tx.table('suppliers').toArray();
        for (const supplier of suppliers) {
          if (supplier.updatedAt === undefined) {
            await tx.table('suppliers').put({
              ...supplier,
              updatedAt: supplier.createdAt ?? now,
            });
          }
        }

        // Backfill products
        const products = await tx.table('products').toArray();
        for (const product of products) {
          if (product.updatedAt === undefined) {
            await tx.table('products').put({ ...product, updatedAt: product.createdAt ?? now });
          }
        }

        // Backfill expenses : pas de createdAt ??? on utilise `date`
        const expenses = await tx.table('expenses').toArray();
        for (const expense of expenses) {
          if (expense.updatedAt === undefined) {
            await tx.table('expenses').put({ ...expense, updatedAt: expense.date ?? now });
          }
        }
      });
  }

  /**
   * R??initialise compl??tement la base de donn??es
   * ?????? ?? utiliser uniquement pour les tests ou le debug
   */
  async clearAll(): Promise<void> {
    await this.delete();
    await this.open();
  }

  /**
   * Exporte toutes les donn??es en JSON
   * Utile pour les backups offline
   */
  async exportData(): Promise<Record<string, unknown>> {
    const exported: Record<string, unknown> = {};

    exported.invoices = await this.invoices.toArray();
    exported.invoiceItems = await this.invoiceItems.toArray();
    exported.clients = await this.clients.toArray();
    exported.suppliers = await this.suppliers.toArray();
    exported.products = await this.products.toArray();
    exported.expenses = await this.expenses.toArray();
    exported.emails = await this.emails.toArray();
    exported.emailTemplates = await this.emailTemplates.toArray();
    exported.calendarEvents = await this.calendarEvents.toArray();
    exported.userProfile = await this.userProfile.toArray();
    exported.chatMessages = await this.chatMessages.toArray();

    return exported;
  }

  /**
   * Importe des donn??es depuis un backup JSON
   * @param data - Donn??es export??es pr??c??demment
   */
  async importData(data: Record<string, unknown>): Promise<void> {
    try {
      if (data.invoices) {
        await this.invoices.bulkPut(data.invoices as Invoice[]);
      }
      if (data.invoiceItems) {
        await this.invoiceItems.bulkPut(data.invoiceItems as InvoiceItem[]);
      }
      if (data.clients) {
        await this.clients.bulkPut(data.clients as Client[]);
      }
      if (data.suppliers) {
        await this.suppliers.bulkPut(data.suppliers as Supplier[]);
      }
      if (data.products) {
        await this.products.bulkPut(data.products as Product[]);
      }
      if (data.expenses) {
        await this.expenses.bulkPut(data.expenses as Expense[]);
      }
      if (data.emails) {
        await this.emails.bulkPut(data.emails as Email[]);
      }
      if (data.emailTemplates) {
        await this.emailTemplates.bulkPut(data.emailTemplates as EmailTemplate[]);
      }
      if (data.calendarEvents) {
        await this.calendarEvents.bulkPut(data.calendarEvents as CalendarEvent[]);
      }
      if (data.userProfile) {
        await this.userProfile.bulkPut(data.userProfile as UserProfile[]);
      }
      if (data.chatMessages) {
        await this.chatMessages.bulkPut(data.chatMessages as ChatMessage[]);
      }
    } catch (error) {
      console.error("Erreur lors de l'importation des donn??es:", error);
      throw error;
    }
  }

  /**
   * Calcule les statistiques globales de la base
   * Utile pour l'audit et le monitoring
   */
  async getStatistics() {
    return {
      invoices: await this.invoices.count(),
      clients: await this.clients.count(),
      suppliers: await this.suppliers.count(),
      products: await this.products.count(),
      expenses: await this.expenses.count(),
      emails: await this.emails.count(),
      calendarEvents: await this.calendarEvents.count(),
    };
  }
}

