/**
 * Hook Authentification GitHub - useGitHubAuth
 * ??? Gestion compl??te du cycle de vie d'authentification GitHub
 * ??? Gestion d'erreurs avec fallback
 * ??? Synchronisation avec Firestore
 * ??? R??cup??ration du profil utilisateur
 */

import {
  browserLocalPersistence,
  browserSessionPersistence,
  setPersistence,
  signInWithPopup,
  signOut,
  type User,
} from "firebase/auth";
import { useCallback, useEffect, useMemo, useState } from "react";
import { auth, db, githubProvider } from "../firebase";
import {
  AuthErrorHandler,
  GitHubAuthService,
  type UserProfile,
} from "../services/authService";

export interface UseGitHubAuthState {
  user: User | null;
  profile: UserProfile | null;
  isLoading: boolean;
  error: Error | null;
  isAuthenticated: boolean;
}

export interface UseGitHubAuthMethods {
  loginWithGitHub: (rememberMe?: boolean) => Promise<void>;
  logout: () => Promise<void>;
  clearError: () => void;
  refreshProfile: () => Promise<void>;
}

/**
 * Hook personnalis?? pour l'authentification GitHub
 * @returns ??tat et m??thodes d'authentification
 */
export function useGitHubAuth(): UseGitHubAuthState & UseGitHubAuthMethods {
  const [user, setUser] = useState<User | null>(null);
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);

  const authService = useMemo(() => new GitHubAuthService(auth, db), []);

  // Effet : ??coute les changements d'authentification Firebase
  useEffect(() => {
    const unsubscribe = auth.onAuthStateChanged((firebaseUser) => {
      void (async () => {
        try {
          setIsLoading(true);
          setUser(firebaseUser);

          if (firebaseUser) {
            // R??cup??rer le profil utilisateur depuis Firestore
            const userProfile = await authService.getUserProfile(
              firebaseUser.uid,
            );
            setProfile(userProfile);
            setError(null);
          } else {
            setProfile(null);
          }
        } catch (err) {
          console.error("Erreur r??cup??ration profil:", err);
          setError(
            err instanceof Error ? err : new Error("Erreur authentification"),
          );
        } finally {
          setIsLoading(false);
        }
      })();

    return () => unsubscribe();
  }, [authService]);

  // Connexion avec GitHub
  const loginWithGitHub = useCallback(
    async (rememberMe = true) => {
      try {
        setIsLoading(true);
        setError(null);

        // Appliquer la persistance
        await setPersistence(
          auth,
          rememberMe ? browserLocalPersistence : browserSessionPersistence,
        );

        const result = await signInWithPopup(auth, githubProvider);
        setUser(result.user);

        // R??cup??rer le profil
        const userProfile = await authService.getUserProfile(result.user.uid);
        setProfile(userProfile);
      } catch (err: unknown) {
        const error =
          err instanceof Error ? err : new Error("Erreur connexion");

        // Gestion sp??cifique des erreurs
        if (AuthErrorHandler.isNetworkError(error)) {
          setError(
            new Error("Erreur r??seau. V??rifiez votre connexion Internet."),
          );
        } else if (AuthErrorHandler.isAccountConflictError(error)) {
          setError(
            new Error("Ce compte GitHub est d??j?? associ?? ?? un autre compte."),
          );
        } else {
          setError(error);
        }

        console.error("Erreur connexion GitHub:", err);
      } finally {
        setIsLoading(false);
      }
    },
    [authService],
  );

  // D??connexion
  const logout = useCallback(async () => {
    try {
      setIsLoading(true);
      await signOut(auth);
      setUser(null);
      setProfile(null);
      setError(null);
    } catch (err) {
      const error =
        err instanceof Error ? err : new Error("Erreur d??connexion");
      setError(error);
      console.error("Erreur d??connexion:", err);
    } finally {
      setIsLoading(false);
    }
  }, []);

  // Efface les erreurs
  const clearError = useCallback(() => {
    setError(null);
  }, []);

  // Rafra??chir le profil utilisateur
  const refreshProfile = useCallback(async () => {
    if (!user) {
      return;
    }

    try {
      setIsLoading(true);
      const userProfile = await authService.getUserProfile(user.uid);
      setProfile(userProfile);
    } catch (err) {
      const error =
        err instanceof Error ? err : new Error("Erreur rafra??chissement");
      setError(error);
    } finally {
      setIsLoading(false);
    }
  }, [user, authService]);

  return {
    user,
    profile,
    isLoading,
    error,
    isAuthenticated: !!user,
    loginWithGitHub,
    logout,
    clearError,
    refreshProfile,
  };
}

/**
 * Hook pour des cas d'usage simple (just login/logout)
 * Version all??g??e de useGitHubAuth
 */
export function useSimpleGitHubAuth() {
  const { user, isLoading, error, isAuthenticated, loginWithGitHub, logout } =
    useGitHubAuth();

  return {
    user,
    isLoading,
    error,
    isAuthenticated,
    login: loginWithGitHub,
    logout,
  };
}

/**
 * Hook pour centraliser la logique de routage des vues
 * Remplace le switch/case de 140+ lignes dans AppShell
 *
 * Utilisation :
 * const ViewComponent = useViewRouter(currentView, syncData)
 */

import React, { Suspense, useEffect } from 'react';
import LoadingFallback from '../components/LoadingFallback';
import { saveOAuthToken, type OAuthToken } from '../services/cloudSyncService';
import { useAppStore } from '../store/appStore';
import { InvoiceStatus, type UserProfile } from '../types';
import type { AppShellSyncResult } from './useAppShellSync';

const DEFAULT_USER_PROFILE: UserProfile = {
  companyName: '',
  siret: '',
  address: '',
  email: '',
  phone: '',
};

// Lazy load des managers
const Dashboard = React.lazy(() => import('../components/Dashboard'));
const InvoiceManager = React.lazy(() => import('../components/InvoiceManager'));
const ClientManager = React.lazy(() => import('../components/ClientManager'));
const SupplierManager = React.lazy(() => import('../components/SupplierManager'));
const ProductManager = React.lazy(() => import('../components/ProductManager'));
const AccountingManager = React.lazy(() => import('../components/AccountingManager'));
const EmailManager = React.lazy(() => import('../components/EmailManager'));
const CalendarManager = React.lazy(() => import('../components/CalendarManager'));
const SettingsManager = React.lazy(() => import('../components/SettingsManager'));
const AIAssistant = React.lazy(() => import('../components/AIAssistant'));
const BankReconciliationManager = React.lazy(
  () => import('../components/BankReconciliationManager')
);
const VATDashboardManager = React.lazy(() => import('../components/VATDashboardManager'));

export type ViewType =
  | 'dashboard'
  | 'invoices'
  | 'clients'
  | 'suppliers'
  | 'products'
  | 'accounting'
  | 'emails'
  | 'calendar'
  | 'settings'
  | 'ai_assistant'
  | 'bank_reconciliation'
  | 'vat_dashboard';

interface ViewRouterProps {
  currentView: ViewType;
  syncData: AppShellSyncResult;
  onNavigate: (view: ViewType) => void;
}

/**
 * Retourne le composant React ?? afficher pour la vue actuelle
 */
export const useViewRouter = ({
  currentView,
  syncData,
  onNavigate,
}: ViewRouterProps): React.ReactNode => {
  // R??cup??rer les setters du store pour les composants qui les attendent
  const {
    setInvoices,
    setClients,
    setSuppliers,
    setProducts,
    setExpenses,
    setEmails,
    setEmailTemplates,
    setCalendarEvents,
    setUserProfile,
  } = useAppStore();

  // ????????? GESTION DU CALLBACK OAUTH ?????????
  useEffect(() => {
    // V??rifier si nous sommes sur l'URL de callback (plus simple que de modifier le router complet)
    if (
      window.location.pathname === '/oauth-callback' ||
      window.location.hash.includes('access_token')
    ) {
      const hash = window.location.hash.substring(1);
      const params = new URLSearchParams(hash);
      const accessToken = params.get('access_token');
      const state = params.get('state');

      if (accessToken && state) {
        try {
          const { provider } = JSON.parse(atob(state));
          const expiresIn = parseInt(params.get('expires_in') ?? '3600', 10);

          const token: OAuthToken = {
            provider,
            accessToken,
            expiresAt: Date.now() + expiresIn * 1000,
          };

          saveOAuthToken(token);

          // Nettoyer l'URL et fermer la popup ou rediriger
          if (window.opener) {
            window.opener.postMessage({ type: 'OAUTH_SUCCESS', provider }, window.location.origin);
            window.close();
          } else {
            window.location.hash = '';
            window.location.pathname = '/';
          }
        } catch (e) {
          console.error('Erreur lors du parsing du state OAuth', e);
        }
      }
    }
  }, []);

  const renderView = (): React.ReactNode => {
    switch (currentView) {
      case 'dashboard':
        return (
          <Dashboard
            invoices={syncData.invoices}
            products={syncData.products}
            expenses={syncData.expenses}
            events={syncData.calendarEvents}
            onNavigate={onNavigate}
            userProfile={syncData.userProfile ?? DEFAULT_USER_PROFILE}
            onSaveInvoice={syncData.saveInvoice}
          />
        );

      case 'invoices':
        return (
          <InvoiceManager
            invoices={syncData.invoices}
            setInvoices={setInvoices}
            clients={syncData.clients}
            userProfile={syncData.userProfile ?? DEFAULT_USER_PROFILE}
            products={syncData.products}
            onSave={syncData.saveInvoice}
            onDelete={syncData.deleteInvoice}
          />
        );

      case 'clients':
        return (
          <ClientManager
            clients={syncData.clients}
            invoices={syncData.invoices}
            onSave={syncData.saveClient}
            onDelete={syncData.deleteClient}
          />
        );

      case 'suppliers':
        return (
          <SupplierManager
            suppliers={syncData.suppliers}
            setSuppliers={setSuppliers}
            expenses={syncData.expenses}
            onSave={syncData.saveSupplier}
            onDelete={syncData.deleteSupplier}
          />
        );

      case 'products':
        return (
          <ProductManager
            products={syncData.products}
            onSave={syncData.saveProduct}
            onDelete={syncData.deleteProduct}
          />
        );

      case 'accounting':
        return (
          <AccountingManager
            expenses={syncData.expenses}
            setExpenses={setExpenses}
            invoices={syncData.invoices}
            suppliers={syncData.suppliers}
            userProfile={syncData.userProfile ?? DEFAULT_USER_PROFILE}
            clients={syncData.clients}
            onSaveExpense={syncData.saveExpense}
            onDeleteExpense={syncData.deleteExpense}
          />
        );

      case 'emails':
        return (
          <EmailManager
            emails={syncData.emails}
            setEmails={setEmails}
            templates={syncData.emailTemplates}
            setTemplates={setEmailTemplates}
            clients={syncData.clients}
            invoices={syncData.invoices}
            userProfile={syncData.userProfile ?? DEFAULT_USER_PROFILE}
            onSaveEmail={syncData.saveEmail}
            onDeleteEmail={syncData.deleteEmail}
            onSaveTemplate={syncData.saveEmailTemplate}
            onDeleteTemplate={syncData.deleteEmailTemplate}
          />
        );

      case 'calendar':
        return (
          <CalendarManager
            events={syncData.calendarEvents}
            setEvents={setCalendarEvents}
            clients={syncData.clients}
            onSaveEvent={syncData.saveCalendarEvent}
            onDeleteEvent={syncData.deleteCalendarEvent}
          />
        );

      case 'settings':
        return (
          <SettingsManager
            userProfile={syncData.userProfile ?? DEFAULT_USER_PROFILE}
            setUserProfile={setUserProfile}
            onSaveProfile={syncData.saveUserProfile}
            allData={{
              invoices: syncData.invoices,
              clients: syncData.clients,
              suppliers: syncData.suppliers,
              products: syncData.products,
              expenses: syncData.expenses,
            }}
            setAllData={{
              setInvoices,
              setClients,
              setSuppliers,
              setProducts,
              setExpenses,
            }}
          />
        );

      case 'ai_assistant':
        return <AIAssistant />;

      case 'bank_reconciliation':
        return (
          <BankReconciliationManager
            invoices={syncData.invoices}
            onMarkInvoicePaid={(id: string) => {
              const invoice = syncData.invoices.find((i) => i.id === id);
              if (invoice) {
                syncData.saveInvoice({ ...invoice, status: InvoiceStatus.PAID });
              }
            }}
          />
        );

      case 'vat_dashboard':
        return (
          <VATDashboardManager
            invoices={syncData.invoices}
            userProfile={syncData.userProfile ?? DEFAULT_USER_PROFILE}
          />
        );

      default:
        return (
          <Dashboard
            invoices={syncData.invoices}
            products={syncData.products}
            expenses={syncData.expenses}
            events={syncData.calendarEvents}
            onNavigate={onNavigate}
            userProfile={syncData.userProfile ?? DEFAULT_USER_PROFILE}
          />
        );
    }
  };

  // Wrap toujours dans Suspense pour lazy loading
  return <Suspense fallback={<LoadingFallback />}>{renderView()}</Suspense>;
};

